-- Poems batch 286
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3a58f727-3ae8-44dd-99d5-332c787ec195','端硯銘','鄭魁','宋','宋诗','song-poetry','','[]','仙翁種玉芝，耕得紫玻璃。',48,'全唐诗/poet.song.251000.json','["仙翁種玉芝，耕得紫玻璃。", "磨出海鯨血，鑿成天馬蹄。", "潤應通月窟，洗合就雲溪。", "常恐魍魎奪，山行亦自携。"]'),
('fa336534-f45d-4eb3-8da8-5d011eeed02a','句  其一','釋守恭','宋','宋诗','song-poetry','','[]','布髪人來絕，銜花鹿去多。',12,'全唐诗/poet.song.251000.json','["布髪人來絕，銜花鹿去多。"]'),
('e410e017-d757-4297-a06f-bd979aead9aa','句  其二','釋守恭','宋','宋诗','song-poetry','','[]','影落楊侯宅，根連覺帝居。',12,'全唐诗/poet.song.251000.json','["影落楊侯宅，根連覺帝居。"]'),
('7828ff6f-dcd7-4811-b058-73ca271f5993','絕句','朱池寺僧','宋','宋诗','song-poetry','','[]','孤燈寂寂夜堂深，寒雨瀟瀟響竹林。',32,'全唐诗/poet.song.251000.json','["孤燈寂寂夜堂深，寒雨瀟瀟響竹林。", "文抵浮生只如此，不須哀怨動悲音。"]'),
('e852a225-9962-4092-8c69-6c8a312c4f6f','與玉泉長老','歐陽景','宋','宋诗','song-poetry','','[]','金鑾來覓玉泉書，金玉相逢價倍殊。',32,'全唐诗/poet.song.251000.json','["金鑾來覓玉泉書，金玉相逢價倍殊。", "到了不干藤蔓事，葫蘆自去纏葫蘆。"]'),
('71bc7193-d626-4e5f-9894-7d3423e013f6','句  其一','歐陽景','宋','宋诗','song-poetry','','[]','清明時節正穠芳。',8,'全唐诗/poet.song.251000.json','["清明時節正穠芳。"]'),
('947ef7e0-7fde-4aa9-a2b3-06e970966063','句  其二','歐陽景','宋','宋诗','song-poetry','','[]','最是風流堪賞處，美人收作裛衣香。',16,'全唐诗/poet.song.251000.json','["最是風流堪賞處，美人收作裛衣香。"]'),
('841611f9-ea60-4598-9981-8205a15688ec','句  其三','歐陽景','宋','宋诗','song-poetry','','[]','徧向蜀都呈巧樣，被人翻入錦紋頭。',16,'全唐诗/poet.song.251000.json','["徧向蜀都呈巧樣，被人翻入錦紋頭。"]'),
('1833aa59-20d2-40f3-9741-076c83379ff6','句','無名氏','宋','宋诗','song-poetry','','[]','文章却似呼延贊，風貌全同富相公。',16,'全唐诗/poet.song.251000.json','["文章却似呼延贊，風貌全同富相公。"]'),
('d8d65581-67d4-4fcb-abfe-8e16a9f76f37','無題','張崇','宋','宋诗','song-poetry','','[]','群山起伏朝靈嶽，恰似千官奉至尊。',32,'全唐诗/poet.song.251000.json','["群山起伏朝靈嶽，恰似千官奉至尊。", "吳蜀未平宜假手，願將餘力致乾坤。"]'),
('a71a3b27-77f9-4f0d-8b74-1fb0d31bf64e','王仙君壇','林傑','宋','宋诗','song-poetry','','[]','羽客已登雲路去，丹砂草木盡凋殘。',32,'全唐诗/poet.song.251000.json','["羽客已登雲路去，丹砂草木盡凋殘。", "不知千歲歸何日，空使時人掃舊壇。"]'),
('93578e18-56b9-4da3-a4b0-a74ab3c76b6d','七夕','林傑','宋','宋诗','song-poetry','','["\u4e03\u5915\u60c5\u4eba\u8282", "\u4e03\u5915\u8282", "\u4e09\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','七夕今朝看碧霄，牽牛織女渡河橋。',32,'全唐诗/poet.song.251000.json','["七夕今朝看碧霄，牽牛織女渡河橋。", "家家乞巧望秋月，穿盡紅絲幾萬條。"]'),
('bd410d4f-19aa-4162-95fc-0ba5b5be3946','牡丹','楊軒','宋','宋诗','song-poetry','','[]','楊妃歌舞態，西子巧讒魂。',48,'全唐诗/poet.song.251000.json','["楊妃歌舞態，西子巧讒魂。", "利劍砍不斷，餘妖鍾此根。", "光華日已盛，欄檻豈長存。", "寄語尋芳者，須知松柏尊。"]'),
('bfde2958-5abc-44b6-817a-dc98e88b79a9','一日曲','楊軒','宋','宋诗','song-poetry','','[]','妾家鄧侯國，肯愧邯鄲姝。',240,'全唐诗/poet.song.251000.json','["妾家鄧侯國，肯愧邯鄲姝。", "世本富繒綺，嬌愛比明珠。", "十五學組紃，未嘗開戶樞。", "十六失所適，姓名傾里閭。", "十七善歌舞，使君邀宴娛。", "自茲著樂府，不得同羅敷。", "凉溫忽荏苒，屢接朝大夫。", "相歡不及情，何異逢路衢。", "昨日一見郎，目色曾不渝。", "結愛從此篤，暫隔猶恐疏。", "如何遂從官，去涉千里途。", "郎跨青驄馬，妾乘白雪駒。", "送郎郎未遠，別妾妾仍孤。", "不如水中鱗，雙雙依綠蒲。", "不如雲間鵠，兩兩下平湖。", "魚鳥尚可託，妾今誰與俱。", "去去約春華，終朝怨日賒。", "一心思君子，便擬見梅花。", "梅花幾時吐，頻掐闌干數。", "東風若見郎，重爲歌金縷。"]'),
('338d47f8-7922-4c4e-9d4c-dbcdb5b5eefe','句','楊軒','宋','宋诗','song-poetry','','[]','解照日月不照處，獨明天地未明時。',16,'全唐诗/poet.song.251000.json','["解照日月不照處，獨明天地未明時。"]'),
('472871d0-96e1-4621-9194-1e52818046e8','句  其一','南鄭殿丞','宋','宋诗','song-poetry','','[]','青鳥幾傳王母信，白鵝曾換右軍書。',16,'全唐诗/poet.song.251000.json','["青鳥幾傳王母信，白鵝曾換右軍書。"]'),
('a2d7917d-0c35-4b7d-84c2-febfd7cbfccf','句  其二','南鄭殿丞','宋','宋诗','song-poetry','','[]','近闕已瞻龍虎氣，思鄉猶望斗牛星。',16,'全唐诗/poet.song.251000.json','["近闕已瞻龍虎氣，思鄉猶望斗牛星。"]'),
('609ca615-ae49-4676-aab2-b2859e6c7099','句  其一','楊黎州','宋','宋诗','song-poetry','','[]','山川百蠻國，雨露九天書。',12,'全唐诗/poet.song.251000.json','["山川百蠻國，雨露九天書。"]'),
('88fc73ef-68f0-4e66-91d8-caa2b752b4a0','句  其二','楊黎州','宋','宋诗','song-poetry','','[]','胡越自爲迢遞國，參商元是別離星。',16,'全唐诗/poet.song.251000.json','["胡越自爲迢遞國，參商元是別離星。"]'),
('5b6e4f2b-02e1-4c56-a366-67d482a84730','句  其三','楊黎州','宋','宋诗','song-poetry','','[]','天上羲輪都易識，人間堯曆自難逢。',16,'全唐诗/poet.song.251000.json','["天上羲輪都易識，人間堯曆自難逢。"]'),
('e9893e3f-f8a8-4d31-8c6d-be82caf2b4da','句  其四','楊黎州','宋','宋诗','song-poetry','','[]','部中車雨春無潤，天上星郎夜損光。',16,'全唐诗/poet.song.251000.json','["部中車雨春無潤，天上星郎夜損光。"]'),
('af2735e9-eeda-422d-a2e7-dbd4fcb1bb03','句  其五','楊黎州','宋','宋诗','song-poetry','','[]','頓纓狂走鹿，吐沫倦遊鱗。',12,'全唐诗/poet.song.251000.json','["頓纓狂走鹿，吐沫倦遊鱗。"]'),
('9b7a4828-8ee9-4aa2-91d7-972e7fb99048','句  其六','楊黎州','宋','宋诗','song-poetry','','[]','遠別苦驚雲聚散，相逢多悟月盈虧。',16,'全唐诗/poet.song.251000.json','["遠別苦驚雲聚散，相逢多悟月盈虧。"]'),
('99a4d7cd-77cb-4c2c-945f-bb2656b13a78','句  其七','楊黎州','宋','宋诗','song-poetry','','[]','剛腸欺竹葉，衰鬢怯蘆花。',12,'全唐诗/poet.song.251000.json','["剛腸欺竹葉，衰鬢怯蘆花。"]'),
('5a4398d4-75af-4d36-b8d5-cf3c84223215','句  其八','楊黎州','宋','宋诗','song-poetry','','[]','一斑早寄湘川竹，萬點空遺峴首碑。',16,'全唐诗/poet.song.251000.json','["一斑早寄湘川竹，萬點空遺峴首碑。"]'),
('b8f51b5f-647b-4a96-bf6f-08f46ecc3924','句  其九','楊黎州','宋','宋诗','song-poetry','','[]','若非琥珀休爲枕，不是琉璃莫作屏。',16,'全唐诗/poet.song.251000.json','["若非琥珀休爲枕，不是琉璃莫作屏。"]'),
('86bbecef-7e1d-4708-959a-68c21849e6c2','句  其一○','楊黎州','宋','宋诗','song-poetry','','[]','人歸漢后黄金屋，燕在盧家白玉堂。',16,'全唐诗/poet.song.251000.json','["人歸漢后黄金屋，燕在盧家白玉堂。"]'),
('f5d67858-22ea-4e00-acf5-5c7809d791ee','句','楊萬畢','宋','宋诗','song-poetry','','[]','千里暮雲山已黑，一燈孤館酒初醒。',16,'全唐诗/poet.song.251000.json','["千里暮雲山已黑，一燈孤館酒初醒。"]'),
('f1a9012f-45f2-4d5d-b366-da65979c275c','題陳相鄠杜別業壁','張宗尹','宋','宋诗','song-poetry','','[]','喬松翠竹絕纖埃，門對南山盡日開。',32,'全唐诗/poet.song.251000.json','["喬松翠竹絕纖埃，門對南山盡日開。", "應是主人貪報國，功成名遂不歸來。"]'),
('6fc5de59-8040-4a17-ac55-cb68ee054fda','句','張宗尹','宋','宋诗','song-poetry','','[]','大書文字隄防老，剩買田園準備閒。',16,'全唐诗/poet.song.251000.json','["大書文字隄防老，剩買田園準備閒。"]'),
('769c41e8-156b-4618-a406-64709ee3c82a','句','楊獻民','宋','宋诗','song-poetry','','[]','縣官伐木入煙蘿，匠石須材盡日磨。',16,'全唐诗/poet.song.251000.json','["縣官伐木入煙蘿，匠石須材盡日磨。"]'),
('96091e28-b9c9-4cca-8154-b8385f87c4ea','永州有感','廖齊','宋','宋诗','song-poetry','','[]','下馬連聲叩竹門，主人何事感遺恩。',32,'全唐诗/poet.song.251000.json','["下馬連聲叩竹門，主人何事感遺恩。", "回頭泣向兒童道，重見甘棠舊子孫。"]'),
('6b351d48-7ada-4124-a383-eae6badbc0ef','戲張天驥','朱定國','宋','宋诗','song-poetry','','[]','羨公飄蕩一孤舟，來作錢塘十日游。',64,'全唐诗/poet.song.251000.json','["羨公飄蕩一孤舟，來作錢塘十日游。", "水洗禪心都眼凈，山供詩筆總眉愁。", "雪中乘興真聊爾，春盡思歸都罷休。", "何事却尋朱處士，種魚萬尾橘千頭。"]'),
('81b81158-786e-4cbd-8b01-69c0303c118c','書郵亭壁','周仲美','宋','宋诗','song-poetry','','[]','愛妾不愛子，爲問此何理。',84,'全唐诗/poet.song.251000.json','["愛妾不愛子，爲問此何理。", "棄官更棄妻，人情寧可已。", "永訣泗之濱，遺言空在耳。", "三載無朝昏，孤幃淚如洗。", "婦人義從夫，一節誓生死。", "江鄉感殘春，腸斷晚煙起。", "回望太華峰，不知幾千里。"]'),
('87370832-ceff-416f-afbd-65c4a2404680','答外','郭暉妻','宋','宋诗','song-poetry','','[]','碧紗窗下啟緘封，尺紙從頭徹尾空。',32,'全唐诗/poet.song.251000.json','["碧紗窗下啟緘封，尺紙從頭徹尾空。", "應是仙郎懷別恨，憶人全在不言中。"]'),
('b5a40848-27eb-4a93-a079-69ab9f60f6b0','題鴛鴦浦溆圖','無名氏','宋','宋诗','song-poetry','','[]','睡足鴛鴦各欲飛，水花欹岸兩三枝。',32,'全唐诗/poet.song.251000.json','["睡足鴛鴦各欲飛，水花欹岸兩三枝。", "多情公子因乘興，寫出江春日暖時。"]'),
('c326b75d-ec46-4264-a8d5-c2ad4758fcd0','贈尼還俗','史君實','宋','宋诗','song-poetry','','[]','脫却霞裾著綉裙，仙凡從此路歧分。',64,'全唐诗/poet.song.251000.json','["脫却霞裾著綉裙，仙凡從此路歧分。", "蛾眉再畫當時月，蟬鬢重梳舊日雲。", "玉貌緩將鸞鏡照，錦衣兼把麝香薰。", "屏幃乍得蕭郎愛，更沒心情憶老君。"]'),
('a725d379-0e4a-493d-a178-58b70ba7faa7','句  其一','孫山','宋','宋诗','song-poetry','','[]','盤古榜中同進士，伏羲手裏探花郎。',16,'全唐诗/poet.song.251000.json','["盤古榜中同進士，伏羲手裏探花郎。"]'),
('3fb0576f-d4bc-4dd7-8397-600f42ab092c','句  其二','孫山','宋','宋诗','song-poetry','','[]','解名盡處是孫山，君名更在孫山外。',16,'全唐诗/poet.song.251000.json','["解名盡處是孫山，君名更在孫山外。"]'),
('608f8d80-9d8a-4b2e-b548-1d82fa4c11f8','句  其三','孫山','宋','宋诗','song-poetry','','[]','幸頼聖恩收拾了，這回含笑入黄泉。',16,'全唐诗/poet.song.251000.json','["幸頼聖恩收拾了，這回含笑入黄泉。"]'),
('67a0c349-1a21-46c6-b14e-6c98c3a043d2','句  其四','孫山','宋','宋诗','song-poetry','','[]','分開秋水國，映斷夕陽天。',12,'全唐诗/poet.song.251000.json','["分開秋水國，映斷夕陽天。"]'),
('6425b724-aacf-4303-b94e-7117bf541636','句  其五','孫山','宋','宋诗','song-poetry','','[]','結宇孤峰上，安禪巨浪間。',12,'全唐诗/poet.song.251000.json','["結宇孤峰上，安禪巨浪間。"]'),
('7c8a1c99-b0e1-41cc-9714-df83b47a54d9','鄭州','無名氏','宋','宋诗','song-poetry','','[]','南北更無三座寺，東西只有一條街。',32,'全唐诗/poet.song.251000.json','["南北更無三座寺，東西只有一條街。", "四時八節無筵席，半夜三更有界牌。"]'),
('b1630421-ca63-4e2d-be68-21489707612e','句  其一','無名氏','宋','宋诗','song-poetry','','[]','憲州渾如枉死市，岢嵐彷彿似陽間。',16,'全唐诗/poet.song.251000.json','["憲州渾如枉死市，岢嵐彷彿似陽間。"]'),
('a4e78df2-d743-4496-8773-0064c1b74d65','句  其二','無名氏','宋','宋诗','song-poetry','','[]','雞足斜分三道水，蛇腰慢轉一條街。',16,'全唐诗/poet.song.251000.json','["雞足斜分三道水，蛇腰慢轉一條街。"]'),
('8a8f182f-d4d0-4979-8d45-f31fd14b7fb5','句  其三','無名氏','宋','宋诗','song-poetry','','[]','沙堆套裏三條路，石炭烟中兩座城。',16,'全唐诗/poet.song.251000.json','["沙堆套裏三條路，石炭烟中兩座城。"]'),
('d83da33c-b28b-4726-bc24-c6d3cfb8f28f','句  其四','無名氏','宋','宋诗','song-poetry','','[]','土洞裏頭行十日，山棚上面住三年。',16,'全唐诗/poet.song.251000.json','["土洞裏頭行十日，山棚上面住三年。"]'),
('20b12e21-1448-4872-b353-1978968097a2','題太行山石壁','無名氏','宋','宋诗','song-poetry','','[]','太行千里連芳草，獨酌一杯天地小。',32,'全唐诗/poet.song.251000.json','["太行千里連芳草，獨酌一杯天地小。", "醉卧花間人不知，黄鶑啼破春山曉。"]'),
('f9e418f6-2524-417d-af5b-e44c8b7b8c61','絕句','蔡州道人','宋','宋诗','song-poetry','','[]','爛柯真訣妙通神，一局曾經幾度春。',32,'全唐诗/poet.song.251000.json','["爛柯真訣妙通神，一局曾經幾度春。", "自出洞來無敵手，得饒人處且饒人。"]'),
