('12318be3-6549-4683-8059-838e1a209ad1','山居  其一一','淳藏主','宋','宋诗','song-poetry','','[]','幽巖靜坐來馴虎，古澗經行自狎鷗。',32,'全唐诗/poet.song.251000.json','["幽巖靜坐來馴虎，古澗經行自狎鷗。", "不是忘機能絕念，大都投老得心休。"]'),
('7def8480-6574-45c2-afae-b170c9a920ab','山居  其一二','淳藏主','宋','宋诗','song-poetry','','[]','怕寒嬾剃髼鬆髮，愛煖頻添榾柮柴。',32,'全唐诗/poet.song.251000.json','["怕寒嬾剃髼鬆髮，愛煖頻添榾柮柴。", "栗色伽梨撩亂掛，誰能勞苦强安排。"]'),
('df26539e-ba6a-4c33-a13d-d7f8ad9a178d','題雁蕩龍鼻水','肱禪師','宋','宋诗','song-poetry','','[]','雨足雲收得暫閒，謾將頭角寄空山。',32,'全唐诗/poet.song.251000.json','["雨足雲收得暫閒，謾將頭角寄空山。", "鼻端一滴無多子，引得人人到此間。"]'),
('517daa62-afef-4b0e-a768-816bdf79a582','貽老僧','信禪師','宋','宋诗','song-poetry','','[]','俗臘知多少，龐眉擁毳袍。',48,'全唐诗/poet.song.251000.json','["俗臘知多少，龐眉擁毳袍。", "看經嫌字小，問事愛聲高。", "暴日終無厭，登階漸覺勞。", "自言曾少壯，游嶽兩三遭。"]'),
('d95ee779-0d90-46c5-96d5-ce9c8d92d4fe','題壁  其一','和庵主','宋','宋诗','song-poetry','','["\u8861\u5c71"]','自從南嶽來雪竇，二十餘年不下山。',32,'全唐诗/poet.song.251000.json','["自從南嶽來雪竇，二十餘年不下山。", "兩處居庵身已老，又尋幽谷養衰殘。"]'),
('eced66a5-e759-4fb0-a502-500a262d3363','題壁  其二','和庵主','宋','宋诗','song-poetry','','[]','十方世界目前寬，拋却雲庵過別山。',32,'全唐诗/poet.song.251000.json','["十方世界目前寬，拋却雲庵過別山。", "三事壞衣穿處補，一條藜杖伴清閒。"]'),
('1b929934-523f-4786-b0bc-83a2642a6e72','題壁  其三','和庵主','宋','宋诗','song-poetry','','[]','黄皮裹骨一常僧，壞衲蒙頭百慮澄。',32,'全唐诗/poet.song.251000.json','["黄皮裹骨一常僧，壞衲蒙頭百慮澄。", "年老嬾能頻對客，攀蘿又上一崚嶒。"]'),
('a339ed84-fcf1-4515-a12d-35ca0b27b511','永和縣上巳','王駕','宋','宋诗','song-poetry','','[]','記得蘭亭祓禊辰，今朝兼是永和春。',32,'全唐诗/poet.song.251000.json','["記得蘭亭祓禊辰，今朝兼是永和春。", "一觴一詠無詩侶，病倚山窗憶故人。"]'),
('c2d126e0-d2a5-4c5a-bdf1-ce3eb01be35d','四時詩 春','徐瓘','宋','宋诗','song-poetry','','[]','風吹細浪低田麥，雨過初分淺水秧。',32,'全唐诗/poet.song.251000.json','["風吹細浪低田麥，雨過初分淺水秧。", "紅樹半開桃臉嫩，綠波深映柳絲長。"]'),
('4c28a741-1b76-422e-ba9d-63a71f403746','四時詩 夏','徐瓘','宋','宋诗','song-poetry','','[]','林垂紫李玉成蹊，水映紅榴石近溪。',32,'全唐诗/poet.song.251000.json','["林垂紫李玉成蹊，水映紅榴石近溪。", "深棟雙雙飛燕語，陰槐綠樹萬蟬嘶。"]'),
('29ef542e-b4b6-46af-a495-642677bc846c','四時詩 秋','徐瓘','宋','宋诗','song-poetry','','[]','紅飄亂葉樹連枝，雨著疏花菊遶籬。',32,'全唐诗/poet.song.251000.json','["紅飄亂葉樹連枝，雨著疏花菊遶籬。", "蓬轉恨多饒白髮，鴻歸數處寄新詩。"]'),
('30155472-c256-418f-8bcb-ba1f4754ed50','四時詩 冬','徐瓘','宋','宋诗','song-poetry','','[]','飛花雪片落梅殘，興發歌樓酒量寬。',32,'全唐诗/poet.song.251000.json','["飛花雪片落梅殘，興發歌樓酒量寬。", "磯石釣魚觀凍手，衣蓑綠映暮江寒。"]'),
('e22b21ba-e3b7-4449-b69a-17bb427d6fdf','偶書','徐瓘','宋','宋诗','song-poetry','','[]','明中悟理造忱誠，性覺通真見即行。',64,'全唐诗/poet.song.251000.json','["明中悟理造忱誠，性覺通真見即行。", "生不生來空是境，有無有處化爲城。", "榮枯現夢因緣想，色相求心妄執情。", "名與實亡都在道，盲聾苦學漫營營。"]'),
('4f753035-906b-4d33-92eb-db3aba759733','次韻吳叔廉山村','許存我','宋','宋诗','song-poetry','','[]','田繞青山好住家，短籬疏圃接丘麻。',64,'全唐诗/poet.song.251000.json','["田繞青山好住家，短籬疏圃接丘麻。", "煙村遠近棲鴉亂，竹岸高低飛鷺斜。", "泉噴石間巖湧雪，霧浮堤外柳吹花。", "連雲碧色秋光冷，眠犢黄昏草長芽。"]'),
('60a067e3-fed5-4bf2-9041-d8e9916bbd8a','題謝先生白雲庵','曹道沖','宋','宋诗','song-poetry','','[]','桃源洞口武陵人，跳出紅塵二十春。',64,'全唐诗/poet.song.251000.json','["桃源洞口武陵人，跳出紅塵二十春。", "但喜白雲深有趣，不知青眼近來親。", "丹砂已向坤爐伏，玉汞先從坎鼎烹。", "活計一張焦尾外，碧壇三尺禮星辰。"]'),
('765ea417-2e21-4165-9295-5846c0c983d6','陶公醉石','無名氏','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五字高吟酒一瓢，廬山千古想風標。',32,'全唐诗/poet.song.251000.json','["五字高吟酒一瓢，廬山千古想風標。", "至今門外青青柳，不爲東風肯折腰。"]'),
('fd692091-6ec9-4bf5-98a1-ff0a7f3b291c','靖州歌','無名氏','宋','宋诗','song-poetry','','[]','小娘子，葉底花，無事出來喫盞茶。',16,'全唐诗/poet.song.251000.json','["小娘子，葉底花，無事出來喫盞茶。"]'),
('0d5ee83f-9973-41ec-a29b-761c5ef3e435','油污衣','無名氏','宋','宋诗','song-poetry','','[]','一點清油污白衣，斑斑駮駮使人疑。',32,'全唐诗/poet.song.251000.json','["一點清油污白衣，斑斑駮駮使人疑。", "縱饒洗遍千江水，爭似當初不污時。"]'),
('f6f36708-20e5-4751-b3c1-bb9c0b6e5541','絕句','釋惟茂','宋','宋诗','song-poetry','','[]','四面峰巒翠入雲，一溪流水漱山根。',32,'全唐诗/poet.song.251000.json','["四面峰巒翠入雲，一溪流水漱山根。", "老僧只恐山移去，日午先教掩寺門。"]'),
('1b403ffe-ab4e-4ce5-9b33-4ae1ca2f3854','三鴉鎮題壁','無名氏','宋','宋诗','song-poetry','','[]','二年憔悴在三鴉，無米無錢怎養家。',32,'全唐诗/poet.song.251000.json','["二年憔悴在三鴉，無米無錢怎養家。", "每日兩餐唯是藕，看看口裏出蓮花。"]'),
('b90ebf7a-12eb-474b-bf87-c03fabc0a790','和孝狗歌','無名氏','宋','宋诗','song-poetry','','[]','慈烏反哺古所稱，不聞乳狗能效顰。',96,'全唐诗/poet.song.251000.json','["慈烏反哺古所稱，不聞乳狗能效顰。", "鹿坡王氏世吉人，乞得乳狗於良鄰。", "良鄰家貧併日食，狗母長饑骨柴立。", "乳狗食竟掉尾歸，嘔食餵母使母肥。", "朝餐歸嘔暮復續，獸類之中潁考叔。", "紛紛養志多缺如，慚愧四足之韓盧。"]'),
('a6bb5ac5-b3b0-4ab0-b9e1-2e12b550d0ad','傷雙燕','無名氏','宋','宋诗','song-poetry','','[]','燕燕于飛春欲暮，終日呢喃語如訴。',120,'全唐诗/poet.song.251000.json','["燕燕于飛春欲暮，終日呢喃語如訴。", "但聞寄淚來瀟湘，不聞有意如烈婦。", "夏氏狂兒好游獵，彈射飛禽類幾絕。", "梁間雙燕銜泥至，飛鏃傷雄當兒戲。", "雌燕視之兀如癡，不能人言人不知。", "門前陂水清且泚，一飛徑溺澄瀾底。", "傷哉痛恨應未休，安得化作呂氏女，手刃其頭報夫仇。"]'),
('ede5c5f8-36bf-4af1-b1ab-6508e1cf5dca','天柱雉兒行','利書記','宋','宋诗','song-poetry','','[]','當年江上揚風舲，淮山望極排空青。',384,'全唐诗/poet.song.251000.json','["當年江上揚風舲，淮山望極排空青。", "今登天柱賞潜皖，元是吾家翡翠屏。", "禪叢一室因棲寄，選勝尋幽辨真僞。", "虛廊揩蘚讀殘碑，三百年前刊異事。", "此山開闢至唐初，乾元中作金仙居。", "彭門大師曰崇惠，裁基創始成茅廬。", "牛頭道化將雄鎮，浮世勞生未知信。", "乘開石上誦蓮文，非謂疏慵效精進。", "空山白晝接清宵，壞衲披肩度寂寥。", "玲瓏宛轉斷人慮，七軸圓音震海潮。", "奇哉有物名緣會，錦繡毛衣勝綵繪。", "常伴山雞與鷓鴣，優游飲啄烟霞外。", "山梁疇昔歎時哉，此日祇園應世來。", "昂頭斂翼傍禪石，下風側聽忘驚猜。", "醍醐灑盡燒心火，暮去朝還無不可。", "宜成永向佛菩提，春燕秋鴻豈知我。", "俄聞荒草蛻其身，夢魂夜告生爲人。", "幽奇溪石驗端的，右脅遺翎跡尚新。", "妙齡自厭居民俗，祝髮依師隠林麓。", "他經雖授難遽通，唯有芬陀利精熟。", "師因嘆息省前緣，法種慈熏豈偶然。", "立名定體標殊特，靈休表示爲佳傳。", "閑行宴坐何超脫，古鑑無塵罷揮拂。", "登高臨遠快幽情，滿目風光舊時物。"]'),
('085b212b-96b7-45e1-b905-876951179a17','冬日雷雨','段油','宋','宋诗','song-poetry','','[]','劈面同雲布，雨共雪無數。',48,'全唐诗/poet.song.251000.json','["劈面同雲布，雨共雪無數。", "雷又似打鼓，風又似拽鋸。", "雹子遍四郊，電光照四處。", "晚了定似晴，天也撰不去。"]'),
('2500517f-0d62-42c8-8edd-238cfca63038','自題懶愚室','何師韞','宋','宋诗','song-poetry','','["\u8861\u5c71"]','君不見南嶽懶殘師，佯狂啖殘食。',126,'全唐诗/poet.song.251000.json','["君不見南嶽懶殘師，佯狂啖殘食。", "鼻涕任垂頤，懶爲俗人拭。", "又不見愚溪子柳子，堂堂古遺直。", "以愚名溪山，于今慕其德。", "二子真吾師，欲見不可得。", "唯有懶愚樹，終日對顔色。", "齊威勤讀書，輪扁巧斵輪。", "勤巧動心志，何如懶愚貞。", "衰年髮已皤，行少坐時多。", "亦欲傚勤巧，奈此懶愚何。"]'),
('2a47bc78-c0c0-4b62-893f-8c580b8878fc','失假山偈','何師韞','宋','宋诗','song-poetry','','[]','片石亡來歲月深，昔時來覓到如今。',32,'全唐诗/poet.song.251000.json','["片石亡來歲月深，昔時來覓到如今。", "誰知只在家山裏，枉費工夫別處尋。"]'),
('cb78bf94-03a8-48c8-8c0c-3af973fb09f4','題沈烏盆尸股','李氏子','宋','宋诗','song-poetry','','[]','洪州沈烏盆，塑佛捨三尊。',24,'全唐诗/poet.song.251000.json','["洪州沈烏盆，塑佛捨三尊。", "一朝饑凍死，衣不庇其臀。"]'),
('46dc22b4-4c3d-4d65-99c9-2f8d3713d527','浄明寺','邊郎中','宋','宋诗','song-poetry','','[]','疏篁葱蒨雲添潤，亂石玲瓏蘚借斑。',32,'全唐诗/poet.song.251000.json','["疏篁葱蒨雲添潤，亂石玲瓏蘚借斑。", "小有洞從仇穴入，妙峰頂對德雲間。"]'),
('49230ba2-082e-4b64-aedb-007daf19ac95','句','釋惠隆','宋','宋诗','song-poetry','','[]','繞砌淺莎鳴促織，斷檐殘雨挂遊絲。',16,'全唐诗/poet.song.251000.json','["繞砌淺莎鳴促織，斷檐殘雨挂遊絲。"]'),
('3a97b459-8afc-4374-9a2a-837f48bdb889','句','釋文或','宋','宋诗','song-poetry','','[]','十年弓劍爲誰苦，萬里山河不自由。',16,'全唐诗/poet.song.251000.json','["十年弓劍爲誰苦，萬里山河不自由。"]'),
('8b87eefe-0afc-4602-8f98-ebd7dff27797','句','文喜','宋','宋诗','song-poetry','','[]','一向亂雲尋不得，幾番臨水待歸來。',16,'全唐诗/poet.song.251000.json','["一向亂雲尋不得，幾番臨水待歸來。"]'),
('1bc42445-4f2a-49a1-ae94-54cb3eb9979f','自題詩集','釋宗美','宋','宋诗','song-poetry','','[]','新集芻蕘六百篇，冥搜疑到不還天。',32,'全唐诗/poet.song.251000.json','["新集芻蕘六百篇，冥搜疑到不還天。", "多慚未得騷人旨，虛役身心五十年。"]'),
('afb424aa-ac9e-499e-8b9a-35f7aac3f8c3','題延福寺','釋宗美','宋','宋诗','song-poetry','','[]','倚檻寒松偃，連雲一徑橫。',24,'全唐诗/poet.song.251000.json','["倚檻寒松偃，連雲一徑橫。", "就中圖不得，窗戶入江聲。"]'),
('7f161865-40dc-4ec7-ad96-b68879969b47','句','釋宗美','宋','宋诗','song-poetry','','[]','浣紗舊曲何人笛，一一隨風到客舟。',16,'全唐诗/poet.song.251000.json','["浣紗舊曲何人笛，一一隨風到客舟。"]'),
('99814cd0-cc3e-43ef-9c05-02f88767b298','句','耿仙芝','宋','宋诗','song-poetry','','[]','淺水短蕪調馬地，淡雲微雨養花天。',16,'全唐诗/poet.song.251000.json','["淺水短蕪調馬地，淡雲微雨養花天。"]'),
('f05441e0-fc10-4faf-b9ab-3cbc483ec98c','榴花洞','魏萬','宋','宋诗','song-poetry','','[]','江山巧秀入禪扃，四望仙源畫未真。',64,'全唐诗/poet.song.251000.json','["江山巧秀入禪扃，四望仙源畫未真。", "萬疊好峰侵碧落，一條流水隔紅塵。", "澗邊鹿跡知何代，洞口榴花鎮似春。", "自恨聲名尚牽鎖，無因長對社中人。"]'),
('c1986fba-6838-4aab-bb0f-f10a98d8a6b6','皇恩寺','潘誠','宋','宋诗','song-poetry','','[]','睿澤覃來數百年，海山高處有祇園。',64,'全唐诗/poet.song.251000.json','["睿澤覃來數百年，海山高處有祇園。", "禪林自是三三界，塵世誰知十二門。", "詩客迢迢尋義路，禪翁特特起談軒。", "香爐頂上垂東注，萬派分明出一源。"]'),
('7ad5791f-07f4-4a77-b3d4-32c37b5184c8','句','釋子耶','宋','宋诗','song-poetry','','[]','松欺臘雪千年古，竹掃溪風六月寒。',16,'全唐诗/poet.song.251000.json','["松欺臘雪千年古，竹掃溪風六月寒。"]'),
('bcca12c3-42b1-48d6-a23a-3ff326b9cdce','劍池','徐忻','宋','宋诗','song-poetry','','[]','劍去池空一水寒，游人到此凭闌干。',32,'全唐诗/poet.song.251000.json','["劍去池空一水寒，游人到此凭闌干。", "年來是事消磨盡，只有青山好靜看。"]'),
('fe25536c-a251-4536-91c6-5f7d4d6b5139','句','徐忻','宋','宋诗','song-poetry','','[]','著衣輕有暈，入水淡無痕。',12,'全唐诗/poet.song.251000.json','["著衣輕有暈，入水淡無痕。"]'),
('adc154ad-5324-4ad0-8097-0b1b4f4153d7','句','李榮','宋','宋诗','song-poetry','','[]','國人久倚東園望，擬築沙堤到廣陵。',16,'全唐诗/poet.song.251000.json','["國人久倚東園望，擬築沙堤到廣陵。"]'),
('7b8b891c-a77d-4ab2-ac0d-d3035383a913','挽敦夫','蔡光啟','宋','宋诗','song-poetry','','[]','人物於今嘆渺然，孤墳宿草已生烟。',32,'全唐诗/poet.song.251000.json','["人物於今嘆渺然，孤墳宿草已生烟。", "日暮行人道傍舍，應何年少共談禪。"]'),
('0b3c88c4-0fc2-412f-b9ed-7131eb517135','梵王宮','吳山','宋','宋诗','song-poetry','','[]','靈鰲戴出梵王宮，殿閣崔巍百世雄。',64,'全唐诗/poet.song.251000.json','["靈鰲戴出梵王宮，殿閣崔巍百世雄。", "額古澤心頒建武，地鍾元氣孕鴻濛。", "雲連吳楚江山秀，水接滄溟海日紅。", "我欲楞伽分半榻，汲泉煮茗話真空。"]'),
('6d189c4e-b046-4f0d-8091-9d3f8fee8dfa','句','吳山','宋','宋诗','song-poetry','','[]','外列千區民庶巷，中藏萬載帝王家。',16,'全唐诗/poet.song.251000.json','["外列千區民庶巷，中藏萬載帝王家。"]'),
('b39ec101-fe31-4899-920f-88c103880703','詩一首','無名氏','宋','宋诗','song-poetry','','[]','山行似覺鳥聲殊，漸近神仙簡寂居。',64,'全唐诗/poet.song.251000.json','["山行似覺鳥聲殊，漸近神仙簡寂居。", "門外長溪容浄足，山腰苦筍耿盤蔬。", "喬崧定有藏丹處，大石仍存拜斗餘。", "弟子蒼髯年八十，養生世世授遺書。"]'),
('107277fc-9331-4988-af3c-43b7de7592bc','句','無名氏','宋','宋诗','song-poetry','','[]','浮雲有意藏山頂，流水無聲入稻田。',32,'全唐诗/poet.song.251000.json','["浮雲有意藏山頂，流水無聲入稻田。", "古木微風時起籟，諸峰落日盡藏烟。"]'),
('3260eaf1-1286-4d77-9c97-2cea3a256499','句','程端','宋','宋诗','song-poetry','','[]','郡城好處西州無，兩江回合東南隅。',16,'全唐诗/poet.song.251000.json','["郡城好處西州無，兩江回合東南隅。"]'),
('f1e0c884-1dc3-4192-968c-d3d9e923263b','溫泉','查蔤','宋','宋诗','song-poetry','','[]','浴罷臨泉一整冠，令人搔首憶長安。',32,'全唐诗/poet.song.251000.json','["浴罷臨泉一整冠，令人搔首憶長安。", "御湯摇蕩雙龍影，疑是胡兒簇馬鞍。"]'),
('3259cfa9-ba73-467b-b590-83b03df4ad40','句','查蔤','宋','宋诗','song-poetry','','[]','潼關一敗胡兒喜，簇馬驪山看御湯。',16,'全唐诗/poet.song.251000.json','["潼關一敗胡兒喜，簇馬驪山看御湯。"]'),
('abd1354d-d090-4f83-b0d5-54e87a8dbc0a','句','崔仰之','宋','宋诗','song-poetry','','[]','山色監巴迥，江流入漢清。',12,'全唐诗/poet.song.251000.json','["山色監巴迥，江流入漢清。"]'),
('f789e6ff-e2ee-4403-a37a-a94c88bec101','句','李簡','宋','宋诗','song-poetry','','[]','山遶一城藏古寺，江連二水送孤舟。',16,'全唐诗/poet.song.251000.json','["山遶一城藏古寺，江連二水送孤舟。"]'),
('e9ad22a4-c9db-4624-88fc-1dabc6eb2296','上太師公相生辰詩十首  其一','無名氏','宋','宋诗','song-poetry','','[]','地靈人傑産忠良，瑞靄龍蟠虎踞鄉。',64,'全唐诗/poet.song.251000.json','["地靈人傑産忠良，瑞靄龍蟠虎踞鄉。", "天欲中興神降岳，世將嘉靖弼生商。", "和羹早報梅花信，壽酒先飛柏葉觴。", "笑指山南成带礪，龐眉與國等綿長。"]'),
('c39a1cf7-3acc-4267-879d-f35ea2a81a14','上太師公相生辰詩十首  其二','無名氏','宋','宋诗','song-poetry','','[]','運鍾百六擾神州，國祚當時劇贅旒。',64,'全唐诗/poet.song.251000.json','["運鍾百六擾神州，國祚當時劇贅旒。", "獨藉奇材支大厦，允資巨力障橫流。", "嘯呼左袒安劉氏，指顧南冠縶楚囚。", "整頓乾坤康濟了，千齡翊宋永同休。"]'),
('96474e2d-c47e-4c87-ba67-7eca75f8ed56','上太師公相生辰詩十首  其三','無名氏','宋','宋诗','song-poetry','','[]','揚眉吐氣快生風，萬里歸來虎帳中。',64,'全唐诗/poet.song.251000.json','["揚眉吐氣快生風，萬里歸來虎帳中。", "竭節任公營大計，解紛排難激丹衷。", "只憑忠信行蠻貊，遂使聲名等岱崧。", "一德一心天所祐，定知福壽享無窮。"]'),
('247ea009-dea3-47f1-9b9d-7b94d2e16942','上太師公相生辰詩十首  其四','無名氏','宋','宋诗','song-poetry','','[]','交歡鄰國獨推誠，不顧流言斷必行。',64,'全唐诗/poet.song.251000.json','["交歡鄰國獨推誠，不顧流言斷必行。", "直欲生靈躋壽域，聊將干舞解平城。", "坐扶國祚齊箕翼，立挽天河洗甲兵。", "和議一成夷夏福，蒼生擊壤咏昇平。"]'),
('e4e0fafe-2c5e-48ca-bafd-8b99985d6979','上太師公相生辰詩十首  其五','無名氏','宋','宋诗','song-poetry','','[]','談笑能令國勢强，一時忠義凜秋霜。',64,'全唐诗/poet.song.251000.json','["談笑能令國勢强，一時忠義凜秋霜。", "挽回騩馭還長樂，直把鴻勳紀太常。", "問寢東朝宮殿曉，來庭北使塞垣長。", "輔成孝弟光寰宇，竹帛仍傳萬世芳。"]'),
('0ec62dba-c94a-40dd-b090-a50d302ee202','上太師公相生辰詩十首  其六','無名氏','宋','宋诗','song-poetry','','[]','跋扈驕矜勢糾紛，兵威不戢定將焚。',64,'全唐诗/poet.song.251000.json','["跋扈驕矜勢糾紛，兵威不戢定將焚。", "權歸宥密消兵釁，力埽欃槍息祲氛。", "鴻劍將軍休畫策，捧觴都護罷論勳。", "四方廊廊無餘事，咸仰伊周輔聖君。"]'),
('d845609e-ddd6-4e7c-a605-39eb880cad7b','上太師公相生辰詩十首  其七','無名氏','宋','宋诗','song-poetry','','[]','偃伯靈臺滌翳昏，太平有象更何言。',64,'全唐诗/poet.song.251000.json','["偃伯靈臺滌翳昏，太平有象更何言。", "百神禋祀承天貺，萬里調元識定尊。", "復見漢儀難並舉，請觀周樂足同論。", "秉鈞當軸誠知體，坐使先生道滿門。"]'),
('48c8125d-c00c-491a-9d53-050c75fa9673','上太師公相生辰詩十首  其八','無名氏','宋','宋诗','song-poetry','','[]','騎𡏖蒙蒙一洗空，恢崇儒館闡文風。',64,'全唐诗/poet.song.251000.json','["騎𡏖蒙蒙一洗空，恢崇儒館闡文風。", "正當世祖投戈際，遠邁元和沸鼎中。", "坐使車書同萬里，行看冠蓋襲諸戎。", "我公勳業追王佐，豈比區區頌泮宮。"]'),
('22432ddb-60d0-4b61-a16b-fe29d8a7b240','上太師公相生辰詩十首  其九','無名氏','宋','宋诗','song-poetry','','[]','勤勞王室見周公，報賜宜膺曲阜封。',64,'全唐诗/poet.song.251000.json','["勤勞王室見周公，報賜宜膺曲阜封。", "兆見維秦符佐命，祥開有魏慶疇庸。", "申加井賦恩方洽，倍衍圭腴賞正濃。", "一德君臣千載遇，九州四海仰雲龍。"]'),
('facc883b-8e23-46e0-b288-e046133c0a60','上太師公相生辰詩十首  其一○','無名氏','宋','宋诗','song-poetry','','[]','手扶日月補圜穹，錫第庸旌再造功。',64,'全唐诗/poet.song.251000.json','["手扶日月補圜穹，錫第庸旌再造功。", "樂奏鈞天迎騎擁，詩歌湛露晏堂豐。", "屬車臨幸龍顔喜，拔宅飛升帝眷隆。", "燕雀非惟依託計，華夷億萬頼帡幪。"]'),
('5e5eb165-da62-4b6d-b1b6-beaa1a76f52f','題常山店壁','張惠卿','宋','宋诗','song-poetry','','[]','迢遞投前店，颼飀守破窗。',24,'全唐诗/poet.song.251000.json','["迢遞投前店，颼飀守破窗。", "一燈明復暗，顧影不成雙。"]'),
('5d518005-0297-4cdb-aa7a-e9f912573079','句  其一','無名氏','宋','宋诗','song-poetry','','[]','一色樓臺三十里，不知何處覓孤山。',16,'全唐诗/poet.song.251000.json','["一色樓臺三十里，不知何處覓孤山。"]'),
('bd33c4eb-9a4f-4771-b67a-1bf148aec8df','句  其二','無名氏','宋','宋诗','song-poetry','','[]','地下若逢秦相國，也應不說到沅湘。',16,'全唐诗/poet.song.251000.json','["地下若逢秦相國，也應不說到沅湘。"]'),
('56e77fe7-2164-45c3-964c-a7250554496a','題劉武僖題名後','無名氏','宋','宋诗','song-poetry','','[]','一入侯門海樣深，漫留名字惱行人。',32,'全唐诗/poet.song.251000.json','["一入侯門海樣深，漫留名字惱行人。", "夜來彷彿高唐夢，猶恐行雲意未真。"]'),
('53ec11ce-97cf-434f-a9fc-82bdd91b915d','句','周伯仁','宋','宋诗','song-poetry','','[]','照天不夜梨花月，落地無聲柳絮風。',16,'全唐诗/poet.song.251000.json','["照天不夜梨花月，落地無聲柳絮風。"]'),
('d62d35db-4f04-4b5d-8d37-f064d0067ea1','王文孺臞庵','徐作','宋','宋诗','song-poetry','','[]','藜莧幽人室，丘園隠者居。',48,'全唐诗/poet.song.251000.json','["藜莧幽人室，丘園隠者居。", "一原青嶂合，萬水綠陰疏。", "手把歸田賦，腰懸種樹書。", "桑麻連畛秀，網罟入溪漁。"]'),
('86e105c0-9f71-4df8-badf-29589f77b187','臞庵','沈某','宋','宋诗','song-poetry','','[]','清江繞檻白鷗飛，坐看潮痕上釣磯。',64,'全唐诗/poet.song.251000.json','["清江繞檻白鷗飛，坐看潮痕上釣磯。", "松菊未荒元亮徑，芰荷先製屈平衣。", "窗前楓葉曉初落，亭下鱸魚秋正肥。", "安得從君理蓑笠，櫂歌相趁入烟霏。"]'),
('c531eeae-da15-4004-8fa6-fc9a4031a8a9','觀滄浪亭石感而有作','劉敬','宋','宋诗','song-poetry','','[]','蘇君在朝人不知，蘇君既沒人悲之。',133,'全唐诗/poet.song.251000.json','["蘇君在朝人不知，蘇君既沒人悲之。", "流風遺書見稱道，高文大句爭提撕。", "壁間草隸亦不置，剝苔椎土無棄遺。", "乃知死不與人共利害，而後不爲時所疑。", "滄浪亭空卉木老，古石蒼蒼顔色好。", "無脛猶能千里來，致身忽在都門道。", "帝都王侯好事多，相看自悔取不早。", "君不見吳興長史春襴衫，閉門抱恨長枯槁。"]'),
('fa680369-07b3-4ae6-9085-3cd914d2e21e','遊秀峰寺','劉無降','宋','宋诗','song-poetry','','[]','曉乘輕舸出江城，晚上籃輿却倦行。',32,'全唐诗/poet.song.251000.json','["曉乘輕舸出江城，晚上籃輿却倦行。", "盡日松風響巖谷，小窗聽作亂泉聲。"]'),
('a3eed126-7faf-4f62-bb77-46169c781dd0','吳中寒食','林歆','宋','宋诗','song-poetry','','[]','寒食家家踏曉晴，好風吹我出重城。',64,'全唐诗/poet.song.251000.json','["寒食家家踏曉晴，好風吹我出重城。", "幾灣野水迎人白，數點家山刮眼明。", "已有鴒原聯乘樂，何須鷁尾并橈行。", "山前父老應相笑，爲我頻來學送迎。"]'),
('225123a8-59f7-4247-a8b7-5f340cab19da','白蓮花  其一','釋惠日','宋','宋诗','song-poetry','','[]','神物何由測，芬陀陸地興。',48,'全唐诗/poet.song.251000.json','["神物何由測，芬陀陸地興。", "素芳呈玉雪，梵剎肇丘陵。", "換額從偏霸，懸碑自老僧。", "慇懃勸來者，期使續千燈。"]'),
('99423725-bfee-4646-9d9e-4171b2499140','白蓮花  其二','釋惠日','宋','宋诗','song-poetry','','[]','白羽芬葩陸地蓮，可曾摇曳水中天。',64,'全唐诗/poet.song.251000.json','["白羽芬葩陸地蓮，可曾摇曳水中天。", "肯於素豔分新潔，不與紅酣鬭碧鮮。", "玉井無因期摘實，金園有兆必開先。", "應知瑞與優曇並，一朵騰芳萬古傳。"]'),
('88b65e38-af32-4a31-b88b-19fd38e12902','句','湯黄中','宋','宋诗','song-poetry','','[]','近人方賀厦，如客已驚秋。',12,'全唐诗/poet.song.251000.json','["近人方賀厦，如客已驚秋。"]'),
('b5d2a874-a716-4d46-97f5-15de6a1c5972','遊呪土寺西臺','蒲瀛','宋','宋诗','song-poetry','','[]','偶到城西寺，人言呪土墳。',48,'全唐诗/poet.song.251000.json','["偶到城西寺，人言呪土墳。", "夕陽臺半出，秋草徑才分。", "地下無紅粉，天邊有碧雲。", "徘徊追往事，風急葉紛紛。"]'),
('0b20529a-0385-4525-8227-ea7bff22e5d5','宿靈泉無我軒懷次山','蒲瀛','宋','宋诗','song-poetry','','[]','幽軒著無我，居此合何人。',48,'全唐诗/poet.song.251000.json','["幽軒著無我，居此合何人。", "聞道東山隠，當時此地親。", "心源將止水，世事甚浮雲。", "今日尋遺跡，空餘淡墨春。"]'),
('29d07d21-183b-40f7-be05-257a571863d9','次韻袁升之遊海雲寺鴻慶院山茶之什  其一','蒲瀛','宋','宋诗','song-poetry','','[]','山茶兩本上連空，疊葉棲枝占佛宮。',64,'全唐诗/poet.song.251000.json','["山茶兩本上連空，疊葉棲枝占佛宮。", "雀尾有金輸紺碧，鶴頭無火讓殷紅。", "優于峽茗稱呼異，劣與梅花氣候同。", "誰識諸天雨花外，道人宴坐雪霜中。"]'),
('e4d074cc-a802-4ff5-9035-36e25e57a551','次韻袁升之遊海雲寺鴻慶院山茶之什  其二','蒲瀛','宋','宋诗','song-poetry','','[]','年年花葉炫虛空，歲月循環十二宮。',64,'全唐诗/poet.song.251000.json','["年年花葉炫虛空，歲月循環十二宮。", "對植霜天無頼碧，特開金地可憐紅。", "長春比並何妨別，密雪交加有底同。", "不必傳神呼趙老，君詩元在典刑中。"]'),
('6e1ab9bc-c8a8-4052-8386-a95c46e5e6eb','次韻袁升之遊海雲寺鴻慶院山茶之什  其三','蒲瀛','宋','宋诗','song-poetry','','[]','花開似火半燒空，熒惑飛來失故宮。',64,'全唐诗/poet.song.251000.json','["花開似火半燒空，熒惑飛來失故宮。", "但見洛人誇魏紫，誰知蜀國産真紅。", "肯隨月季無時節，應怪梅花有異同。", "遠挈一罇誰伴我，還從山裏望城中。"]'),
('0c9bf57b-9bbb-4669-9990-564148b00b08','次韻袁升之遊海雲寺鴻慶院山茶之什  其四','蒲瀛','宋','宋诗','song-poetry','','[]','對境那能問色空，山茶花發映蓮宮。',64,'全唐诗/poet.song.251000.json','["對境那能問色空，山茶花發映蓮宮。", "攻餘瑟瑟風摇綠，刑盡猩猩日曬紅。", "大雪迷漫元斗異，千林摇落不雷同。", "何須誑汝老迦葉，分付闍黎一笑中。"]'),
('4cf18d44-2fc0-47c3-ad49-7ade57c106d0','次韻袁升之遊海雲寺鴻慶院山茶之什  其五','蒲瀛','宋','宋诗','song-poetry','','[]','臘月寒冰火滿空，玄冥移種祝融宮。',64,'全唐诗/poet.song.251000.json','["臘月寒冰火滿空，玄冥移種祝融宮。", "雪霜底事論堅白，兒女何知愛軟紅。", "金鼎轉丹應有異，玉沙洗水若爲同。", "細思造物元無物，顛倒繁華掌握中。"]'),
('c066015f-e260-42c9-9692-60208298427b','次韻袁升之遊海雲寺鴻慶院山茶之什  其六','蒲瀛','宋','宋诗','song-poetry','','[]','花發今年喜不空，遨頭肅客上蕭宮。',64,'全唐诗/poet.song.251000.json','["花發今年喜不空，遨頭肅客上蕭宮。", "雪殘千嶂猶連白，風引雙旌欲鬭紅。", "他日勳名三事在，先春和氣萬家同。", "等閒草木蒙湔祓，况入尋常顧盼中。"]'),
('eef467f2-1a32-4f3d-9304-813f814837c8','句','蒲瀛','宋','宋诗','song-poetry','','[]','自爲名都會，況兼山水州。',12,'全唐诗/poet.song.251000.json','["自爲名都會，況兼山水州。"]'),
('e35d478f-fb48-4ddc-8add-67483e983151','大雄寺','奕載','宋','宋诗','song-poetry','','[]','琉璃葉下剪梧桐，綠子青枝掃地空。',64,'全唐诗/poet.song.251000.json','["琉璃葉下剪梧桐，綠子青枝掃地空。", "俗眼如何有青白，好風安得問雌雄。", "物隨塵境工榮顇，人觸心兵戰異同。", "只可輕帆理歸興，暮雲蕭散大江東。"]'),
('c4de0c07-3ea7-40f7-9c5e-04e74d39b715','春帖子','梁君貺','宋','宋诗','song-poetry','','[]','東方和氣斗回杓，龍角中星轉紫霄。',32,'全唐诗/poet.song.251000.json','["東方和氣斗回杓，龍角中星轉紫霄。", "聖主問安天未曉，求衣親護玉宸朝。"]'),
('8a380806-8640-452e-9835-0ed07c0a4b66','贈台倅徐太博','釋長吉','宋','宋诗','song-poetry','','[]','瓊樹聳芳蕤，靈根植仙圃。',120,'全唐诗/poet.song.251000.json','["瓊樹聳芳蕤，靈根植仙圃。", "懿哲藴英才，妙歲沖雲路。", "曲臺峻清秩，峨冠凜奇趣。", "霞城倅郡條，惠愛春榮布。", "心陂萬頃澄，羣物欣翔鷺。", "浮雲擯繁慮，虛舟游太素。", "庾樓明月情，謝塘春草句。", "沙鳥下琴軒，江風起廳樹。", "顒昂出俗操，益爲時賢慕。", "異日柏梁游，淵雲讓孤步。"]'),
('a69dc09b-54a5-477a-b535-cf1c7f42211b','贈郡糾陳員外','釋長吉','宋','宋诗','song-poetry','','[]','耿介藴國器，茲焉糾郡綱。',120,'全唐诗/poet.song.251000.json','["耿介藴國器，茲焉糾郡綱。", "清規稟詩禮，華閥聯簪裳。", "才刃挺銛利，心鑑涵輝光。", "盤錯無以壅，姦邪固難藏。", "民冤積已雪，吏局清如霜。", "彈雀費明月，補履煩干將。", "火烈金益堅，雪深松愈蒼。", "英聲人馳騖，壯氣方激昂。", "凝旒嗣洪業，百辟升賢良。", "孰知隠鵠志，即起摩天翔。"]'),
('69dd74f0-0388-421f-aa0f-e9fd395a087a','題清輝堂','釋長吉','宋','宋诗','song-poetry','','[]','結廬江上棲，江雲日爲侶。',96,'全唐诗/poet.song.251000.json','["結廬江上棲，江雲日爲侶。", "江山相掩映，清輝滿庭戶。", "沙暝見歸禽，潮回聞去櫓。", "落景一簾風，殘雪半江雨。", "中餐啜露葵，午坐烹茶乳。", "少室傳花旨，南華齊物語。", "隠几賾淵源，篆香隨玉麈。", "愛此坐忘歸，東峰月華吐。"]'),
('bc1900a6-e2f2-448b-bc77-27855050c69a','遊栖霞宮','釋長吉','宋','宋诗','song-poetry','','[]','龍虎丹砂煉已成，方瞳綠髮僊骨輕。',64,'全唐诗/poet.song.251000.json','["龍虎丹砂煉已成，方瞳綠髮僊骨輕。", "石床半醉海月冷，芝軒長嘯天風清。", "時泛綠觥陪俠客，未騎赤鯉歸蓬瀛。", "朝簪相訪惜回馭，屢奏瑶琴太古聲。"]'),
('c9440a83-689d-4a17-91a2-5bf944d4caa6','桐柏崇道觀','釋長吉','宋','宋诗','song-poetry','','[]','太帝天壇渤澥連，金霞蒼壁隔埃廛。',64,'全唐诗/poet.song.251000.json','["太帝天壇渤澥連，金霞蒼壁隔埃廛。", "蓬丘不斷青禽位，仙仗時來白虎軿。", "星籥豈惟壺內景，桃花長媚洞中天。", "優游笑把洪崖袂，瞬息人間又幾年。"]'),
('bfe10b25-46cb-476a-b584-77b469c1ccc9','登華頂峰','孟觀','宋','宋诗','song-poetry','','["\u540d\u697c\u3001\u5e99\u5b87", "\u7eaa\u6e38", "\u5199\u666f"]','偶因華頂宿，擡手摘星辰。',24,'全唐诗/poet.song.251000.json','["偶因華頂宿，擡手摘星辰。", "不敢高聲語，恐驚天上人。"]'),
('d54d8bcc-7122-427d-a3e7-9cc85e30d483','石雲','薛如初','宋','宋诗','song-poetry','','[]','洞府標靈萬古傳，石雲呈瑞始何年。',32,'全唐诗/poet.song.251000.json','["洞府標靈萬古傳，石雲呈瑞始何年。", "人間欲待爲霖雨，但看從龍起碧天。"]'),
('be413bfe-09a7-48db-af9b-063260b32f17','凝真宮','薛如初','宋','宋诗','song-poetry','','[]','仙翁曾是便升真，靈跡千年事轉新。',64,'全唐诗/poet.song.251000.json','["仙翁曾是便升真，靈跡千年事轉新。", "碧洞峰前開紫府，清溪門外隔紅塵。", "祥雲瑞靄籠金殿，羽蓋霓旌擁玉晨。", "今日勝遊誠有遇，麻姑留我醉經春。"]'),
('04415ece-187a-4a37-ad7a-b3a41a55cd45','石梁寺','石郊','宋','宋诗','song-poetry','','[]','行破白雲山幾重，僧牀投宿幸相容。',32,'全唐诗/poet.song.251000.json','["行破白雲山幾重，僧牀投宿幸相容。", "泉聲到枕夜無寐，時聽隔林方廣鐘。"]'),
('d8137a02-ead1-457d-8dac-403b4cc97190','題仙居縣南峰','郭明甫','宋','宋诗','song-poetry','','[]','山光竹影交寒輝，下有碧清吹漣漪。',64,'全唐诗/poet.song.251000.json','["山光竹影交寒輝，下有碧清吹漣漪。", "沙痕隠隠白鳥去，石聲鑿鑿扁舟歸。", "蕙蘭發香禪味遠，雲霧吐秀人家稀。", "須知春事不可挽，杜鵑已繞林中飛。"]'),
('3ee57401-a29e-4b4f-824b-944135b11f8b','題樟林寺','玉盤居士','宋','宋诗','song-poetry','','[]','千巖壁立任蒼苔，今日玉盤居士來。',32,'全唐诗/poet.song.251000.json','["千巖壁立任蒼苔，今日玉盤居士來。", "洗斸雲根堪宴坐，不教獨秀在天台。"]'),
('ed71ea22-21bf-420c-82ba-34c07608909b','題金鼇山如畫軒  其一','潘朝英','宋','宋诗','song-poetry','','[]','古木摇陰綠插空，梵宮寂寞草髼鬆。',32,'全唐诗/poet.song.251000.json','["古木摇陰綠插空，梵宮寂寞草髼鬆。", "可憐昔日掀天事，曾對君王跨六龍。"]'),
('f506ce9c-14c5-4758-a179-06cf79ae6a17','題金鼇山如畫軒  其二','潘朝英','宋','宋诗','song-poetry','','[]','春潮暮落海門山，百艇齊飛牡蠣灘。',32,'全唐诗/poet.song.251000.json','["春潮暮落海門山，百艇齊飛牡蠣灘。", "分得魚蝦歸野市，滿江鷗鷺夕陽閒。"]'),
('7d587b40-9aa2-49a6-af0b-2126f9ddb1fe','題金鼇山如畫軒  其三','潘朝英','宋','宋诗','song-poetry','','[]','亂壑收雲接漲瀾，一天風露夜漫漫。',32,'全唐诗/poet.song.251000.json','["亂壑收雲接漲瀾，一天風露夜漫漫。", "金鼇不動涵坤軸，海月騰空萬宇寒。"]'),
('619c5f2c-a1ad-471a-8f6a-f858c82fa4d6','題金鼇山如畫軒  其四','潘朝英','宋','宋诗','song-poetry','','[]','倦客登臨力已疲，高僧故索小窗詩。',32,'全唐诗/poet.song.251000.json','["倦客登臨力已疲，高僧故索小窗詩。", "江山最好君知否，春去秋來烟雨時。"]'),
('57ee25d9-0fa7-4780-8814-8598d9178077','別題','無名氏','宋','宋诗','song-poetry','','[]','休說三江與五湖，平生心眼此中舒。',32,'全唐诗/poet.song.251000.json','["休說三江與五湖，平生心眼此中舒。", "人人總道渾如畫，祇恐丹青畫不如。"]'),
('e18ed4a9-0782-4aa5-8c31-7477f634f978','題甯海瀛巖','無名氏','宋','宋诗','song-poetry','','[]','溫台萬丘壑，走遍成重胝。',144,'全唐诗/poet.song.251000.json','["溫台萬丘壑，走遍成重胝。", "佳山落床頭，咫尺反不知。", "我聞野老說，山乃神石移。", "蓬萊本三峰，一峰今失之。", "上干雲霓秀，下壓鼇背欹。", "夜半見海日，紫暈開咸池。", "魑魅著老木，狂鼯向人啼。", "危亭無遺棟，絕壁無舊題。", "夫子勇過我，竦身敢獨躋。", "我病不能從，夢寐常追隨。", "秋風海上來，霜清鱸正肥。", "行尋越溪鞅，肅此世塵鞿。"]'),
('7095397d-5f96-4274-afc5-c95ac7a60659','題司馬悔橋','無名氏','宋','宋诗','song-poetry','','[]','道書司馬悔，福地在天台。',108,'全唐诗/poet.song.251000.json','["道書司馬悔，福地在天台。", "茲山秀盤古，億載青崔嵬。", "如何越中志，紀載殊未該。", "浪云唐子微，曾過茲橋來。", "奉詔悔輕出，欲勒俗駕回。", "至今名字存，修梁架岩隈。", "圖諜已太戾，土俗尤疏哉。", "以悔明茲橋，大字標板牌。", "流傳愈訛舛，雲笈君試開。"]'),
('bd1fd831-93ca-4c42-a9b9-dbb9157cf825','看弄潮','無名氏','宋','宋诗','song-poetry','','[]','弄罷江潮晚入城，紅旗颭颭白旗輕。',32,'全唐诗/poet.song.251000.json','["弄罷江潮晚入城，紅旗颭颭白旗輕。", "不因會喫翻浪頭，爭得天街鼓樂迎。"]'),
('0c03352c-be2e-4895-8139-c8c5ea5f5546','句','百醉老人','宋','宋诗','song-poetry','','[]','中原戎馬場，故國虎狼窟。',24,'全唐诗/poet.song.251000.json','["中原戎馬場，故國虎狼窟。", "言歸成默傷，念之中心慄。"]'),
('4f0cdc43-9f87-4b61-8606-cdbac6d205ee','廬山白蓮社','釋懷悟','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','晉室陵遲帝紀侵，羣英晦跡匡山陰。',64,'全唐诗/poet.song.251000.json','["晉室陵遲帝紀侵，羣英晦跡匡山陰。", "樓煩大士麾麈尾，十七高賢爭扣几。", "才高孰謂文中龍，返使伊人思謝公。", "烟飛露滴玉池空，雪蓮蘸影摇秋風。"]'),
('aed068cb-43a5-461b-93ba-16b57558bfa0','游金庭觀','馬并','宋','宋诗','song-poetry','','[]','右軍學業隠林丘，世隔年餘景尚幽。',64,'全唐诗/poet.song.251000.json','["右軍學業隠林丘，世隔年餘景尚幽。", "苔鎖一泓殘墨沼，雲遮三級舊書樓。", "欣逢羽客開金闕，快睹仙童侍玉旒。", "自怪今朝脫凡骨，飛身得向洞天遊。"]'),
('b7ed30e9-d4d6-47cb-b706-efe0b3ffa24c','金庭觀','李清叟','宋','宋诗','song-poetry','','[]','山屬蓬壺第幾重，奇峰翠岫繞靈宮。',64,'全唐诗/poet.song.251000.json','["山屬蓬壺第幾重，奇峰翠岫繞靈宮。", "雲藏毛竹深深洞，烟起香爐裊裊風。", "放鶴已歸天漢上，養鵝無復小池中。", "羽人盡得飛章法，神與寥陽路暗通。"]'),
('84309842-5f87-4386-96f3-f1469f50f00e','遊金庭觀','金卞','宋','宋诗','song-poetry','','[]','尋真窮養浩，崇妙路迢迢。',48,'全唐诗/poet.song.251000.json','["尋真窮養浩，崇妙路迢迢。", "洞掩峰千疊，塵分水一條。", "白雲生石壁，飛閣插崖腰。", "隠隠存仙跡，渾疑在碧霄。"]'),
('183f7b20-700c-40c2-a850-837713c0dd7b','遊金庭觀','歐陽建世','宋','宋诗','song-poetry','','[]','右軍平昔愛觀鵝，尚有池塘聚淥波。',32,'全唐诗/poet.song.251000.json','["右軍平昔愛觀鵝，尚有池塘聚淥波。", "但見當時塵跡在，徘徊終日對嵯峨。"]'),
('779ec283-9407-4f62-b062-29bb142974db','游金庭觀','葉參光','宋','宋诗','song-poetry','','[]','迢遞人間入路遥，忽窺仙闕絕塵囂。',64,'全唐诗/poet.song.251000.json','["迢遞人間入路遥，忽窺仙闕絕塵囂。", "事尋奇異彼燕石，文載興崇是晉朝。", "攻藝高樓無筆硯，養鵝靈沼識蒭蕘。", "英雄雖逐年華謝，萬古真風冠碧霄。"]'),
('4fd79c88-4c61-42a0-a992-390a5e1ef488','游金庭觀','李太澄','宋','宋诗','song-poetry','','[]','步步溪山轉幾重，五雲深處敞琳宮。',64,'全唐诗/poet.song.251000.json','["步步溪山轉幾重，五雲深處敞琳宮。", "峰巒秀擁神仙至，門徑清無世俗風。", "晝靜棋聲深院裏，月明琴弄夜堂中。", "丹成仙子無餘事，祇待蟠桃信息通。"]'),
('67abe31b-3ed2-4b03-9b1b-c929485f09f1','端硯','李樸','宋','宋诗','song-poetry','','[]','巖石凝清粹，端然絕世珍。',24,'全唐诗/poet.song.251000.json','["巖石凝清粹，端然絕世珍。", "聲清輕楚玉，色潤勝燕珉。"]'),
('b543c5e5-6151-44f1-b3c8-e7cf6e76a6f0','句  其一','胡澹翁','宋','宋诗','song-poetry','','[]','如今竹閣多清興，紫蟹尖團不數蝦。',16,'全唐诗/poet.song.251000.json','["如今竹閣多清興，紫蟹尖團不數蝦。"]'),
('799d99d4-2f42-4eb7-9a2c-3c85c2709aac','句  其二','胡澹翁','宋','宋诗','song-poetry','','[]','鮭魚還抵店，蝦蟹不論錢。',12,'全唐诗/poet.song.251000.json','["鮭魚還抵店，蝦蟹不論錢。"]'),
('e45e999f-d0fa-4948-926a-1a8a577be762','句  其三','胡澹翁','宋','宋诗','song-poetry','','[]','赤魚白蟹何足數，風味未可松江鱸。',16,'全唐诗/poet.song.251000.json','["赤魚白蟹何足數，風味未可松江鱸。"]'),
