('f26c79dd-2f76-4d5b-9b2f-70583a5d1391','句','李公異','宋','宋诗','song-poetry','','[]','海門礙日山雙聳，江北迎人樹幾行。',16,'全唐诗/poet.song.251000.json','["海門礙日山雙聳，江北迎人樹幾行。"]'),
('8ce9dabb-1055-4171-9dac-b65b91776b1e','句','鮮于能','宋','宋诗','song-poetry','','[]','金山一拳石，石髻出溟漲。',12,'全唐诗/poet.song.251000.json','["金山一拳石，石髻出溟漲。"]'),
('9b6c1cbb-5318-42b6-bea9-7657fd84a851','詠潤州','胡致能','宋','宋诗','song-poetry','','[]','一昨丹陽王氣銷，盡將豪侈謝喧囂。',64,'全唐诗/poet.song.251000.json','["一昨丹陽王氣銷，盡將豪侈謝喧囂。", "衣冠不復宗唐代，父老猶能道晉朝。", "萬歲樓邊誰唱月，千秋橋上自吹簫。", "青山不與興亡事，只共垂楊伴海潮。"]'),
('96870331-5e4d-4280-81dc-32a55233d622','句','胡致能','宋','宋诗','song-poetry','','[]','吳王殿裏笙歌罷，煬帝城邊草木荒。',16,'全唐诗/poet.song.251000.json','["吳王殿裏笙歌罷，煬帝城邊草木荒。"]'),
('53f98299-6eb4-4c31-8e40-9fd3329ef39f','洗心堂','曹翊','宋','宋诗','song-poetry','','[]','清光秀發水雲鄉，不見騷人意未降。',64,'全唐诗/poet.song.251000.json','["清光秀發水雲鄉，不見騷人意未降。", "風壓柳梢低酒舍，月移松影上僧窗。", "山泉漲起潮三尺，野老釣歸魚一雙。", "更待練光斜趁日，坐看金斗熨秋江。"]'),
('37b4c1ba-abb4-4ca0-932a-697b67b90c50','松風亭','曹翊','宋','宋诗','song-poetry','','[]','亭前山影漾江流，亭外雲霞礙舉頭。',64,'全唐诗/poet.song.251000.json','["亭前山影漾江流，亭外雲霞礙舉頭。", "俯石下聽松上籟，隔鄉遥認水邊舟。", "四簷寒送沙汀雨，一徑烟籠寺竹秋。", "此曲此聲應未變，抱琴期與故人游。"]'),
('47b822d8-6970-48c6-b640-3e5c8bd02ee8','句','朱裔','宋','宋诗','song-poetry','','[]','會入天台裏，看予度金山。',12,'全唐诗/poet.song.251000.json','["會入天台裏，看予度金山。"]'),
