('f93d224c-473d-460d-8ebb-baf06b870ef7','句  其五','崔覲','宋','宋诗','song-poetry','','[]','直望漢江三百里，一條如綫下洋州。',16,'全唐诗/poet.song.251000.json','["直望漢江三百里，一條如綫下洋州。"]'),
('738a5863-d2dd-497e-8e43-2f81a23f70c3','句  其一','利州路運判','宋','宋诗','song-poetry','','[]','嘉陵橫其陰，劍門屹其陽。',36,'全唐诗/poet.song.251000.json','["嘉陵橫其陰，劍門屹其陽。", "綠野宋江細，絕磴九隴長。", "黑水環禹迹，青原带秦疆。"]'),
('f1b385a6-2b84-4638-9f09-45c9e11e7d5a','句  其二','利州路運判','宋','宋诗','song-poetry','','[]','蜀道萬里險，黎城千古荒。',12,'全唐诗/poet.song.251000.json','["蜀道萬里險，黎城千古荒。"]'),
('09225faf-352e-42a0-8ede-33e06927b906','南樓','李猷卿','宋','宋诗','song-poetry','','[]','三面江光抱城郭，四圍山勢鎖烟霞。',32,'全唐诗/poet.song.251000.json','["三面江光抱城郭，四圍山勢鎖烟霞。", "馬鞍嶺上渾如錦，繖蓋門前半是花。"]'),
('e2c7f2ba-ba7c-47cd-ba6f-de37091bda32','句','陳士泰','宋','宋诗','song-poetry','','[]','閬州蒼翠與雲齊，閬水連城碧渺瀰。',16,'全唐诗/poet.song.251000.json','["閬州蒼翠與雲齊，閬水連城碧渺瀰。"]'),
('3e2d34b2-accb-4325-a831-685acb77e1d2','琅璫驛','姚清叔','宋','宋诗','song-poetry','','[]','弄臣寧復解輸忠，偶契琅璫一語中。',32,'全唐诗/poet.song.251000.json','["弄臣寧復解輸忠，偶契琅璫一語中。", "富貴難親貧易感，西來方憶曲江公。"]'),
('8194b86e-8e94-4f30-945c-940e43ae89fd','句','呂昌明','宋','宋诗','song-poetry','','[]','豈惟藏兩蜀，亦自限三巴。',12,'全唐诗/poet.song.251000.json','["豈惟藏兩蜀，亦自限三巴。"]'),
('492fbfd4-48a5-42d6-9f1d-a38fd269758f','劍閣','慕容佰才','宋','宋诗','song-poetry','','[]','劍嶺排峰鳥過遲，蜀貪秦詐事堪悲。',32,'全唐诗/poet.song.251000.json','["劍嶺排峰鳥過遲，蜀貪秦詐事堪悲。", "若爲社稷思長計，肯把干將自倒持。"]'),
('12e73187-0648-4ac7-8c4b-0ced9dfd26a8','大劍山','慕容佰才','宋','宋诗','song-poetry','','[]','李勢非嵎虎，公孫是井蛙。',144,'全唐诗/poet.song.251000.json','["李勢非嵎虎，公孫是井蛙。", "聖朝無外戶，夷壤盡爲家。", "疊嶂寧須鏟，停鼖久廢撾。", "原鱗生駱谷，釣駟入彭衙。", "關失千年壯，方來萬里遐。", "商淵寧澒洞，使節偏谽谺。", "岑蔚誰驚鳥，豐茭自樂䴥。", "烽屯開雨雪，樵爨老烟霞。", "帝德朝宗地，仙游上漢槎。", "賞奇酬酒興，摛藻謝詩葩。", "階走楓林葉，窗催桕燭花。", "山亭無刻漏，隠几待鳴鴉。"]'),
('3ed03c2d-5e1b-402f-8d64-6e27adb571a2','元宵','彭永','宋','宋诗','song-poetry','','[]','巴人最重上元時，老稚相携看點詩。',32,'全唐诗/poet.song.251000.json','["巴人最重上元時，老稚相携看點詩。", "行樂歸來天向曉，道傍聞得喚蠶絲。"]'),
('80e027c9-4d58-4365-8f6b-e5230771b7f4','句','楊粹','宋','宋诗','song-poetry','','[]','擊甌樓在碧江隈，樓下江聲寂寞迴。',16,'全唐诗/poet.song.251000.json','["擊甌樓在碧江隈，樓下江聲寂寞迴。"]'),
('ca90b0b8-8ce7-43fb-8acf-61e16217e45b','句  其一','姚彥遊','宋','宋诗','song-poetry','','[]','見說巴南一小州，孤城寂寞字江頭。',16,'全唐诗/poet.song.251000.json','["見說巴南一小州，孤城寂寞字江頭。"]'),
('7e00e9d0-50e5-48d7-9258-4a88886faeac','句  其二','姚彥遊','宋','宋诗','song-poetry','','[]','聞說巴南無一事，助人清思有江山。',16,'全唐诗/poet.song.251000.json','["聞說巴南無一事，助人清思有江山。"]'),
('5220c246-0779-41d8-aa49-8ec77a257deb','句','鄭子信','宋','宋诗','song-poetry','','[]','古人隨水去不返，此字與山留無窮。',16,'全唐诗/poet.song.251000.json','["古人隨水去不返，此字與山留無窮。"]'),
('14469585-f539-4aae-b823-1550726ef0b9','透明巖壁安祿山題記','清遠居士','宋','宋诗','song-poetry','','[]','妖胡作逆罪滔天，翠輦倉皇幸蜀川。',32,'全唐诗/poet.song.251000.json','["妖胡作逆罪滔天，翠輦倉皇幸蜀川。", "千載業緣磨不盡，却來邀福向金仙。"]'),
('8d33813c-fcbe-4f98-aaae-c77acab7610b','仙馬洞','釋法顯','宋','宋诗','song-poetry','','[]','汗血何時別大宛，一嘶洞府已千年。',32,'全唐诗/poet.song.251000.json','["汗血何時別大宛，一嘶洞府已千年。", "區區漢武求良藥，却是閑中駿骨仙。"]'),
('7f5e2a2e-cd93-41d1-a648-4a536a4bec99','繩金寺','黎良知','宋','宋诗','song-poetry','','[]','懸崖結屋層層閣，眺遠開窗面面峰。',32,'全唐诗/poet.song.251000.json','["懸崖結屋層層閣，眺遠開窗面面峰。", "雲起半天齊碧瓦，風生萬壑響長松。"]'),
('71d630a3-40d8-4492-8f6b-520be7413b58','句','黎良知','宋','宋诗','song-poetry','','[]','見說老僧吟更苦，中宵得句喜撞鐘。',16,'全唐诗/poet.song.251000.json','["見說老僧吟更苦，中宵得句喜撞鐘。"]'),
('4b376873-a3cf-40b7-9901-ac97d3c7a606','題東龕院','嚴庾','宋','宋诗','song-poetry','','[]','晚西寒雨濕黄昏，愛睡山僧已閉門。',32,'全唐诗/poet.song.251000.json','["晚西寒雨濕黄昏，愛睡山僧已閉門。", "獨自倚欄還獨笑，男兒心事與誰論。"]'),
('7adba08f-1f47-49ae-8695-cbbb4681114c','句','樂詔','宋','宋诗','song-poetry','','[]','夜深只見燈高下，春盡不知人往還。',16,'全唐诗/poet.song.251000.json','["夜深只見燈高下，春盡不知人往還。"]'),
('f0207a9f-ddc2-4e0c-b47f-da8020bb524c','開元寺留題  其一','無名氏','宋','宋诗','song-poetry','','[]','雙松偃亞老龍起，喚得清風到別樓。',32,'全唐诗/poet.song.251000.json','["雙松偃亞老龍起，喚得清風到別樓。", "尚憶曩年詩酒伴，幾回天際識歸舟。"]'),
('d5a95fd7-6c22-40f5-9250-0340112df178','開元寺留題  其二','無名氏','宋','宋诗','song-poetry','','[]','臺閣相連駕遠空，亂山烟靄夕陽中。',32,'全唐诗/poet.song.251000.json','["臺閣相連駕遠空，亂山烟靄夕陽中。", "眼前風物初非舊，惟有清凉一寺同。"]'),
('20713470-8111-486e-b97a-6ec3d7c0968a','洋州思鄉','竇裕','宋','宋诗','song-poetry','','[]','家依楚水岸，身寄洋州館。',24,'全唐诗/poet.song.251000.json','["家依楚水岸，身寄洋州館。", "望月獨相思，塵襟淚痕滿。"]'),
('317290e0-46e4-4bd6-8a51-68ba34f32ceb','句','宋中行','宋','宋诗','song-poetry','','[]','路轉五盤知地遠，鋪名太薄見人情。',16,'全唐诗/poet.song.251000.json','["路轉五盤知地遠，鋪名太薄見人情。"]'),
('b868579a-78f3-48ad-9523-379005e0317a','劍門關','曹宗旦','宋','宋诗','song-poetry','','[]','鑿開千里地，通得一隅天。',24,'全唐诗/poet.song.251000.json','["鑿開千里地，通得一隅天。", "疊嶂連三峽，重門扼兩川。"]'),
('25a997c1-0f22-4272-ab46-7158060c4246','句','季兌','宋','宋诗','song-poetry','','[]','異事標仙女，靈蹤隠誌公。',12,'全唐诗/poet.song.251000.json','["異事標仙女，靈蹤隠誌公。"]'),
('72636bf5-e819-45a0-aeda-399b5f81171e','壽客','關士容','宋','宋诗','song-poetry','','[]','莫惜朝衣換酒錢，淵明邂逅此花仙。',32,'全唐诗/poet.song.251000.json','["莫惜朝衣換酒錢，淵明邂逅此花仙。", "重陽滿滿杯中泛，一縷黄金是一年。"]'),
('0043768d-910c-433c-8996-ea61646e6ba4','詩一首','李安期','宋','宋诗','song-poetry','','[]','江左君臣筆力雄，一爲宮體便移風。',32,'全唐诗/poet.song.251000.json','["江左君臣筆力雄，一爲宮體便移風。", "始知姬旦無才思，祇把豳詩詠女功。"]'),
('ec4ff072-d343-4f20-a404-e0c7d3dcc5b8','賦白鷺','李安期','宋','宋诗','song-poetry','','[]','漁父家風不設罾，錦鱗爲飯水爲羹。',32,'全唐诗/poet.song.251000.json','["漁父家風不設罾，錦鱗爲飯水爲羹。", "銀袍祇當蓑衣著，自在江湖過一生。"]'),
('d8a7a8d1-1b99-4d4d-8796-0982c5eeb97a','德興邑廨石刻  其一','無名氏','宋','宋诗','song-poetry','','[]','仕宦之身，天涯海畔。',80,'全唐诗/poet.song.251000.json','["仕宦之身，天涯海畔。", "行商之身，南州北縣。", "不如田舍，長拘見面。", "門無官府，身即强健。", "麻麥遍地，豬羊滿圈。", "不知金貴，唯聞粟賤。", "夏新絹衣，秋新米飯。", "安穩眠睡，直千直萬。"]'),
('b718a897-0c68-4af6-8678-3a3e85e6223b','德興邑廨石刻  其二','無名氏','宋','宋诗','song-poetry','','[]','我田我地，我桑我梓。',110,'全唐诗/poet.song.251000.json','["我田我地，我桑我梓。", "只知百里，不知千里。", "我饑有糧，我渴有水。", "百里之官，得人生死。", "孤兒寡婦，一張白紙。", "入著縣門，冤者有理。", "上官不嗔，民即歡欣。", "上官不富，民免辛苦。", "生我父母，養我明府。", "苗稼萋萋，曷東曷西。", "父母之鄉，天子馬蹄。"]'),
('cda4992a-6dff-4f07-baa8-707348fd3d2e','訪隠者','林昉','宋','宋诗','song-poetry','','[]','曉入南山路，松風最好聽。',48,'全唐诗/poet.song.251000.json','["曉入南山路，松風最好聽。", "候扉黄犬睡，尋食老鴉靈。", "童子炊方熟，先生醉未醒。", "借來一榻坐，看盡相牛經。"]'),
('9a032d23-0514-4ae7-93d6-8df0f425f236','秋戍','林昉','宋','宋诗','song-poetry','','[]','軍頭夜點名，新戍起秋程。',48,'全唐诗/poet.song.251000.json','["軍頭夜點名，新戍起秋程。", "月色黄弓甲，風沙黑渭城。", "斷笳清淚滿，落葉此生輕。", "努力供王事，歸來享太平。"]'),
('9c1229b7-c8f7-49e3-bf83-984807374924','老樹','林昉','宋','宋诗','song-poetry','','[]','元是誰人種，枯殘此磵東。',48,'全唐诗/poet.song.251000.json','["元是誰人種，枯殘此磵東。", "半身虛映水，一葉尚摇風。", "著雨禽初散，當暄蟻欲空。", "年時濃綠影，何處夕陽中。"]'),
('5250e040-bf1c-40b6-b8c3-8b3ed6e705be','同鄭魯望聽杜鵑','林昉','宋','宋诗','song-poetry','','[]','每到桃花發，山鵑叫得頻。',48,'全唐诗/poet.song.251000.json','["每到桃花發，山鵑叫得頻。", "今年同聽處，吳下未歸人。", "客淚滴殘月，物情愁暮春。", "胥江有清水，聊與濯衣塵。"]'),
('e788f6c5-26b3-474d-8896-d72b0da70892','山中','林昉','宋','宋诗','song-poetry','','[]','衡門客去懶冠巾，盡日看山自在身。',64,'全唐诗/poet.song.251000.json','["衡門客去懶冠巾，盡日看山自在身。", "飲澗猨來驚照影，泊枝禽起近衝人。", "黑雲欲雨易成晚，紅葉如花不當春。", "卻憶東門牽犬恨，當年何似布衣貧。"]'),
('6e096f03-ce83-4f4b-ae98-afc75788e3ae','泊越浦','林昉','宋','宋诗','song-poetry','','[]','老樹津亭纜客舟，芙蕖香歇蓼花抽。',64,'全唐诗/poet.song.251000.json','["老樹津亭纜客舟，芙蕖香歇蓼花抽。", "越山只作古時翠，胥水半隨人事流。", "別港雁聲天有月，斷橋漁火夜分秋。", "翻然自笑芒鞋脚，十載風波走幾州。"]'),
('e1d17b10-c0bd-4e96-ae28-d8e1215f8e7f','春歸','林昉','宋','宋诗','song-poetry','','[]','南北春歸有許忙，一晴輕策度林塘。',64,'全唐诗/poet.song.251000.json','["南北春歸有許忙，一晴輕策度林塘。", "柳摇別岸東風瘦，花落斷橋流水香。", "老去客游空劍氣，日來心事只詩囊。", "幽情一點雲天遠，獨鳥無聲飛夕陽。"]'),
('ae9577e1-2f51-45e2-b016-0379cf4743fa','贈別','林昉','宋','宋诗','song-poetry','','[]','傍橋買得小溪船，略舉離盃去意懸。',64,'全唐诗/poet.song.251000.json','["傍橋買得小溪船，略舉離盃去意懸。", "一水夕陽紅蕩影，數峰晴樹碧生烟。", "秋聲不斷雲間雁，別恨空長柳外蟬。", "後夜他州看明月，定知相憶未成眠。"]'),
('fbad59b7-3fcd-4d83-89cc-e40dc1c152f0','贈張高士','林昉','宋','宋诗','song-poetry','','[]','短髮蓬蓬戴小冠，客來歡喜愛供看。',64,'全唐诗/poet.song.251000.json','["短髮蓬蓬戴小冠，客來歡喜愛供看。", "鶴孫夜養翎猶濕，童子南歸語尚蠻。", "擊磬花邊禽醒悟，持經窗下竹平安。", "自言薄有耕桑地，無事干人不出山。"]'),
('f24f8ab4-d439-442d-88f2-a916616c6504','登龍山塔寺','林昉','宋','宋诗','song-poetry','','[]','吳越夕陽多遠山，塔樓高處九秋寒。',64,'全唐诗/poet.song.251000.json','["吳越夕陽多遠山，塔樓高處九秋寒。", "江豚吹浪腥風濕，野鳥行空翥雪乾。", "白日潮聲僧老盡，黄埃世路客游難。", "海門航散孤雲落，酒醒不堪深倚欄。"]'),
('7fa324fd-27ee-4378-ae7c-fe9d2a4a9136','春曉','林昉','宋','宋诗','song-poetry','','[]','薄衣初試曉寒輕，雲閣殘陰雨弄晴。',64,'全唐诗/poet.song.251000.json','["薄衣初試曉寒輕，雲閣殘陰雨弄晴。", "落去好花微有恨，生來野草半無名。", "丹心愛國勞難破，白髮欺人鑷又生。", "瘦遶石欄三十匝，綠楊何處脆鶑聲。"]'),
('efcc6e04-8124-4aa9-adae-e545fde5e451','題所寓壁','林昉','宋','宋诗','song-poetry','','[]','鹿羣上遥岑，雲影抵蒼壁。',24,'全唐诗/poet.song.251000.json','["鹿羣上遥岑，雲影抵蒼壁。", "無客來敲門，倚松讀周易。"]'),
('99a894fd-cc07-4872-b438-516fcf819e4d','南屏山畫猿','林昉','宋','宋诗','song-poetry','','[]','古木懸藤臂半鈎，何年影落此山秋。',32,'全唐诗/poet.song.251000.json','["古木懸藤臂半鈎，何年影落此山秋。", "三聲遠憶巴江月，夜半孤舟起客愁。"]'),
('1f3a895e-2e95-4b91-b276-17f96ad9d3fe','山中春曉','林昉','宋','宋诗','song-poetry','','[]','婆餠焦啼曉戶開，冷東風裏惜殘梅。',32,'全唐诗/poet.song.251000.json','["婆餠焦啼曉戶開，冷東風裏惜殘梅。", "片雲祇傍簷頭宿，昨夜何山作雨來。"]'),
('8e4c2bac-c641-4548-9cd1-cec5d0780dc7','雨中過周氏山莊','林昉','宋','宋诗','song-poetry','','[]','吠犬柴門扣未開，滿身風雨立蒼苔。',32,'全唐诗/poet.song.251000.json','["吠犬柴門扣未開，滿身風雨立蒼苔。", "翠禽一箇高枝上，啄得殘桃落地來。"]'),
('c3631d54-dba4-409d-a3b3-8100bbd8a304','送黄吟隠遊吳門','盛烈','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒江買櫂催遄征，何如緩泛六橋尋鷗盟。',164,'全唐诗/poet.song.251000.json','["寒江買櫂催遄征，何如緩泛六橋尋鷗盟。", "侯門懷刺謁掌儐，何如散策孤山探梅信。", "吟隱豫章之耳孫，調高琢句期顓門。", "西江不住來西湖，喚醒晚唐諸老魂。", "有時吐出驚人語，定須貴殺雒京楮。", "膾炙人口徒屬饜，還來隻字不堪煮。", "行吟荏苒歲欲暮，束裝又問吳中路。", "節翁舊有珠履緣，何況薦書袖無數。", "此行一句直萬錢，十句唾手腰可纏。", "歸來卸却揚州鶴，推敲調度權架閣。"]'),
('38bcb0e3-e39b-45ed-b077-a96e801098fd','湖天晚霞','盛烈','宋','宋诗','song-poetry','','[]','鮫人織出綃五色，馮夷不敢閟深澤。',80,'全唐诗/poet.song.251000.json','["鮫人織出綃五色，馮夷不敢閟深澤。", "闖得燭龍歸崦嵫，橫舒幾占半天碧。", "光絢列岑浮紫翠，琉璃倒蘸成琥珀。", "何當乘風掣下來，并州快剪隨意劃。", "製就詩囊百萬箇，分與江湖放吟客。"]'),
('d825015c-9dec-4b6c-836c-af242568ae05','白髮','盛烈','宋','宋诗','song-poetry','','[]','白髮非有種，如何忽自生。',48,'全唐诗/poet.song.251000.json','["白髮非有種，如何忽自生。", "盡從方寸地，蒔此兩三莖。", "場屋債猶欠，山林計未成。", "頭顱知漸醜，羞向鏡中呈。"]'),
('620945a5-526d-4556-8fb7-d07847031ecf','午窗即事','盛烈','宋','宋诗','song-poetry','','[]','午困俄驚囀栗留，東風獨立思悠悠。',64,'全唐诗/poet.song.251000.json','["午困俄驚囀栗留，東風獨立思悠悠。", "蜂搜花醴勤王事，燕拓芹巢爲子謀。", "白髮愁邊添漸密，青春忙裏去如流。", "無言猛拍欄干曲，恰喜長鬚薦茗甌。"]'),
('60462a99-a4bf-47ad-bde7-262170b64ff7','同黄吟隠湖上散步','盛烈','宋','宋诗','song-poetry','','[]','暖翻鴨頂一川晴，喜共長堤緩轡行。',64,'全唐诗/poet.song.251000.json','["暖翻鴨頂一川晴，喜共長堤緩轡行。", "落盡繁紅春結局，傳來太白酒尋盟。", "人于冷淡交偏好，句向蕭閑吟倍清。", "鵜鴂一聲林外喚，短篷歸带夕陽明。"]'),
('536a44e3-f461-4110-80ee-6fd66f97b039','觀下湖漁者','盛烈','宋','宋诗','song-poetry','','[]','漁舠逗曉來相續，短笆亂割春塘淥。',32,'全唐诗/poet.song.251000.json','["漁舠逗曉來相續，短笆亂割春塘淥。", "須留一半還詩翁，要看早晚鴛鴦浴。"]'),
('56598aec-0e98-4091-b64e-4200d833742a','玉閬風書院偶題  其一','盛烈','宋','宋诗','song-poetry','','[]','塔倚翠微椽筆勁，湖吞碧落硯池寬。',32,'全唐诗/poet.song.251000.json','["塔倚翠微椽筆勁，湖吞碧落硯池寬。", "天然調度誰消得，不是吟家出手難。"]'),
('be02c89e-4dba-4bfc-9f15-1e991147a61c','玉閬風書院偶題  其二','盛烈','宋','宋诗','song-poetry','','[]','歲事從他沸似糜，小窗挂起只看詩。',32,'全唐诗/poet.song.251000.json','["歲事從他沸似糜，小窗挂起只看詩。", "不知那樹梅先謝，一片香飛入硯池。"]'),
('e53ae195-6d6a-48d4-afda-fce531a99d52','堤上歸  其一','盛烈','宋','宋诗','song-poetry','','[]','舟橫別港赴鷗約，人立斜陽等燕歸。',32,'全唐诗/poet.song.251000.json','["舟橫別港赴鷗約，人立斜陽等燕歸。", "心事一春拈不出，兩堤楊柳又綿飛。"]'),
('265fe5b9-cb61-4543-92c7-b24b36423aed','堤上歸  其二','盛烈','宋','宋诗','song-poetry','','[]','片雲篩雨過橫塘，襯斷蘋風作晚凉。',32,'全唐诗/poet.song.251000.json','["片雲篩雨過橫塘，襯斷蘋風作晚凉。", "意快短檠推不照，柳邊聽月對啼螿。"]'),
('d9c1e6fd-2399-43df-a24c-23076969f4be','漁父詞','盛烈','宋','宋诗','song-poetry','','[]','曉岸披風駕短篷，平蕪煙浪幾重重。',32,'全唐诗/poet.song.251000.json','["曉岸披風駕短篷，平蕪煙浪幾重重。", "鳴榔莫近荷花浦，鷗鷺早凉眠正濃。"]'),
('1c346760-a136-413f-956c-fe14aba84251','春興','盛烈','宋','宋诗','song-poetry','','[]','涇雲全放兩峰青，灣柳絲金照眼明。',32,'全唐诗/poet.song.251000.json','["涇雲全放兩峰青，灣柳絲金照眼明。", "短棹又隨鷗鷺去，笙歌少處結春盟。"]'),
('e1985299-945a-42c2-a704-22eec027823c','暮天即事','盛烈','宋','宋诗','song-poetry','','[]','東寺鐘聯西寺鳴，前村樹末暝煙平。',32,'全唐诗/poet.song.251000.json','["東寺鐘聯西寺鳴，前村樹末暝煙平。", "天涯倦翼歸無限，只有鴉飛自喚名。"]'),
('07ff541c-64ab-4748-b02c-4fc7e6f2da58','幽庭','盛烈','宋','宋诗','song-poetry','','[]','幽庭鳥蹴梅花片，䔩䔩因風摶復散。',32,'全唐诗/poet.song.251000.json','["幽庭鳥蹴梅花片，䔩䔩因風摶復散。", "貪看立到晝陰移，滿地蒼苔遮一半。"]'),
('7bc23723-6123-41db-860e-151820f4ab77','朔風','盛烈','宋','宋诗','song-poetry','','[]','小窗簾箔護重重，榾柮鑪心蛻骨紅。',32,'全唐诗/poet.song.251000.json','["小窗簾箔護重重，榾柮鑪心蛻骨紅。", "昨夜朔風能凜冽，冰花亦結硯池中。"]'),
('9b5be909-2c09-4400-9d4e-8df5639f779d','晚步段橋','盛烈','宋','宋诗','song-poetry','','[]','垂紅頂上快登臨，拍拍秋光滿袖襟。',32,'全唐诗/poet.song.251000.json','["垂紅頂上快登臨，拍拍秋光滿袖襟。", "伎癢欲吟吟未穩，兩山鐘裏莫雲深。"]'),
('c5f41a80-e711-4be2-93b3-10116aea7410','野寺','李時可','宋','宋诗','song-poetry','','[]','野寺不逢僧，修廊且緩行。',48,'全唐诗/poet.song.251000.json','["野寺不逢僧，修廊且緩行。", "竹藏雙鶴睡，風助一蟬鳴。", "坐石侵衣冷，臨風漱玉清。", "詠歸無限意，新月带星橫。"]'),
('bcc6ae78-f7ed-435e-af76-8008a4307ba4','別余司法','李時可','宋','宋诗','song-poetry','','[]','欲別愁如結，來時眉便開。',48,'全唐诗/poet.song.251000.json','["欲別愁如結，來時眉便開。", "相逢兩無事，且盡十分杯。", "明月今宵共，春風幾日回。", "梅花發牆角，此際望君來。"]'),
('56ead345-88f1-49f2-ad44-18d8d52dc819','雪行','李時可','宋','宋诗','song-poetry','','[]','天寒鴉欲棲，客路尚遲遲。',48,'全唐诗/poet.song.251000.json','["天寒鴉欲棲，客路尚遲遲。", "泥滑蹇馿澀，風斜破帽欹。", "雲藏山斷絕，梅苦雪禁持。", "客裏愁無著，愁邊却有詩。"]'),
('744938b9-fd76-49d9-a2e0-ef851c9102b6','題方漕水閣','李時可','宋','宋诗','song-poetry','','[]','三間水閣傍溪湄，曾倚欄干此賦詩。',32,'全唐诗/poet.song.251000.json','["三間水閣傍溪湄，曾倚欄干此賦詩。", "山色溪光還似舊，惜無詩思似當時。"]'),
('a1b9280d-b182-4b61-a94d-b37e77659423','舟中夜聞讀書','李時可','宋','宋诗','song-poetry','','[]','臨谿一舍竹疎疎，舟過時聞夜讀書。',32,'全唐诗/poet.song.251000.json','["臨谿一舍竹疎疎，舟過時聞夜讀書。", "姓字是誰何必問，定應不是俗人居。"]'),
('1ecad0d8-6506-4705-9d8a-a0a3ec478c07','六朝舊迹','李時可','宋','宋诗','song-poetry','','[]','六朝更代幾興亡，滿地黄花只舊香。',32,'全唐诗/poet.song.251000.json','["六朝更代幾興亡，滿地黄花只舊香。", "水鳥不知人事改，雙飛猶自戀寒塘。"]'),
('fb66a711-ef81-4eb6-90a1-bdcf70b45384','杜鵑花','李時可','宋','宋诗','song-poetry','','[]','杜鵑躑躅正開時，自是山家一段奇。',32,'全唐诗/poet.song.251000.json','["杜鵑躑躅正開時，自是山家一段奇。", "莫據眼前看易厭，帝城只賣擔頭枝。"]'),
('ed1e861d-c5f4-4e8e-91a7-3a12d5c4aebe','擬古','陳宗遠','宋','宋诗','song-poetry','','[]','蠶絲圖利人，利成身已烹。',48,'全唐诗/poet.song.251000.json','["蠶絲圖利人，利成身已烹。", "蛛絲圖網物，網成身益傾。", "漢興弓犬棄，楚亂蕭艾生。", "禍福乃如此，吾道烏能亨。"]'),
('b52d2102-9a65-432f-a559-6fa9ab345da6','有感','陳宗遠','宋','宋诗','song-poetry','','[]','天地不磈立，人爲天地心。',252,'全唐诗/poet.song.251000.json','["天地不磈立，人爲天地心。", "世無經濟學，何以任彌綸。", "沛興園綺隠，淵啟虬髯驚。", "漢唐造草昧，數子留其名。", "我非烟霞徒，息養離世氛。", "我非雲水客，眼空觀劫塵。", "有身必有用，用世非榮身。", "善性自孟子，惡性由荀卿。", "氣質誠有駁，良心乃其純。", "荀卿言治氣，孟子言養心。", "治如治稊稗，惡去善自生。", "養如養佳穀，善長惡亦亡。", "善善而惡惡，孟荀同臭馨。", "安用泥口耳，紛紛爭異名。", "寥寥數千載，塵迹汗簡青。", "麟死不可作，紀例存其文。", "世無公是非，安得真勸懲。", "西漢豈無人，氣節冰雪清。", "東漢豈無人，長厚性質淳。", "特立違時好，心事竟埋堙。", "紛紛瀾倒徒，空贏身後名。"]'),
('05046b36-ee27-4748-9fba-01b23353f190','有感','陳宗遠','宋','宋诗','song-poetry','','[]','呢喃燕賀厦，嘹嚦鴻漸磐。',48,'全唐诗/poet.song.251000.json','["呢喃燕賀厦，嘹嚦鴻漸磐。", "戀主江南暖，來賓塞北寒。", "炎凉有變易，去就無留難。", "勿嫌烏鵲噪，朝朝止屋端。"]'),
('d724ab7f-101b-472f-bba2-52a8d842d136','異獸','陳宗遠','宋','宋诗','song-poetry','','[]','甬東有異獸，俗名訛曰歆。',108,'全唐诗/poet.song.251000.json','["甬東有異獸，俗名訛曰歆。", "其形類猴玃，或謂虎之精。", "逐人求口食，咿啞小兒聲。", "滿望乃謝去，不遂輒生嗔。", "利爪捥人目，烏喙啄其身。", "膏血盡且死，適意方欠伸。", "行道足一迹，深山晝掩門。", "衆疑心是獸，何乃面如人。", "不知椎剝吏，人面而獸心。"]'),
('1da2b34e-20cf-42fc-8927-a6accb1a8c3a','戲同舍與內競','陳宗遠','宋','宋诗','song-poetry','','[]','龍泉函氣清，歐冶吐霞綺。',276,'全唐诗/poet.song.251000.json','["龍泉函氣清，歐冶吐霞綺。", "干將墮龜文，莫邪潜漫理。", "藏鋒金匣夜光芒，銅花玉暈相磨砥。", "雄雌一落東與西，相從不隔千山水。", "憶妾與君差池飛，送君挾策游京畿。", "暮雲空碧雁度遠，畫梁寂寞燕來遲。", "但願月宮分彩色，豈恨霜閨弄落暉。", "君方倦羈旅，妾亦厭枌土。", "錦水鴛鴦巢漢林，綺翼飛翔交媚嫵。", "有時嬌妬不自持，佯嗔不肯舒眉宇。", "逢君貧困泣牛衣，舉案低蛾似頑魯。", "誰知志滿凌暴生，剛腸便不愛卿卿。", "望斷犢車揮麈急，飽負虎嵎攘臂輕。", "松柏故無情，凌霄植根蒂。", "柔蔓托高翹，歲寒忻附麗。", "何爲絲蘿親，反有榮悴異。", "昔日淚霑衣，長嗔失意同寒饑。", "今日衣擁淚，翻怨得意由輕肥。", "炎凉世態得失間，怨君却悔嗔君時。"]'),
('5f3258fe-c5f3-46f6-88de-e7adb2f25642','夢遊月宮','陳宗遠','宋','宋诗','song-poetry','','[]','蜿虹絳彩垂霄路，白波渺渺散寒露。',144,'全唐诗/poet.song.251000.json','["蜿虹絳彩垂霄路，白波渺渺散寒露。", "橫空擲綺結飛梁，靉靆青雲匝風御。", "颺金排玉水晶宮，鸞佩霓襦笑相遇。", "兔停玉杵取玄霜，吳質無端强猜妬。", "窺見腰中三尺冰，便疑斫却婆娑樹。", "桂香廣陌不得留，灼灼修娥謾回顧。", "天孫飛梭織冰紈，帝子吹笙濕香霧。", "笑指瑶臺十二層，只怕結鄰未相許。", "瀲灧金樞煙水寒，會駕飛輪撇波去。"]'),
('0af60b6b-ac30-4829-ab98-2412c8d76481','過橫遠途中','陳宗遠','宋','宋诗','song-poetry','','[]','蠶桑事已過，耕稼老農勤。',48,'全唐诗/poet.song.251000.json','["蠶桑事已過，耕稼老農勤。", "橋斷荒村雨，山埋半嶺雲。", "小松穿石出，野水落田分。", "茅店傾醨酒，相看亦論文。"]'),
('ef177083-baae-4527-804f-538922923fc3','病起','陳宗遠','宋','宋诗','song-poetry','','[]','事業書千卷，生涯菊一籬。',48,'全唐诗/poet.song.251000.json','["事業書千卷，生涯菊一籬。", "約居慳問卜，多病頗知醫。", "看鏡癯添骨，挼髭笑解頤。", "閉門方得趣，不誦北山移。"]'),
('6964f5d0-90e5-4fd4-9c21-5432108ce1fd','送洪宰西歸少歌漁春渡是日風雨','陳宗遠','宋','宋诗','song-poetry','','[]','送客來孤店，疏軒竹數莖。',48,'全唐诗/poet.song.251000.json','["送客來孤店，疏軒竹數莖。", "歸帆出煙雨，群吏立沙汀。", "似我情何悄，如君事最榮。", "待無雲隔岸，須看遠山青。"]'),
('0031d6b9-f56f-449b-a0da-ab5fbd2cdfa3','寺深','陳宗遠','宋','宋诗','song-poetry','','[]','寺深幽寂寂，四月似秋天。',48,'全唐诗/poet.song.251000.json','["寺深幽寂寂，四月似秋天。", "夜久聽山雨，晚來添石泉。", "斷巖風嘯木，疏竹鳥棲煙。", "鐘鼓林梢動，空堂已罷禪。"]'),
('794d1659-e6d9-4680-a20d-0efa413d838b','安仁樓間晚晴時送默齋伯回星江','陳宗遠','宋','宋诗','song-poetry','','[]','已是悲秋客，那堪送遠人。',48,'全唐诗/poet.song.251000.json','["已是悲秋客，那堪送遠人。", "亂山殘照慘，落葉晚風頻。", "去恨隨帆遠，回頭轉意親。", "明朝相憶處，鱗雁達情真。"]'),
('82382167-3308-4034-8579-77a49ba2b3ed','呈豹林伯進齋表叔','陳宗遠','宋','宋诗','song-poetry','','[]','曲逕禪房午，幽風動古林。',48,'全唐诗/poet.song.251000.json','["曲逕禪房午，幽風動古林。", "泉聲落澗靜，磬韻隔雲深。", "空谷留禽語，青山洗客心。", "頓然忘俗想，來此不妨吟。"]'),
('04a1954a-871e-4272-a345-73022bf21d65','資政入村造壽器謾賦','陳宗遠','宋','宋诗','song-poetry','','[]','功成身退從來少，綠野超然洗俗埃。',64,'全唐诗/poet.song.251000.json','["功成身退從來少，綠野超然洗俗埃。", "閑出西疇營六檟，勝傳南極映三槐。", "迎門村婦携兒拜，遮道田翁带犬回。", "競喜鳴珂歸舊隠，爭如鷗鷺不相猜。"]'),
('bcd5bb40-ba5f-42dd-a736-3ccfa70839e2','八月初五日有懷舊事','陳宗遠','宋','宋诗','song-poetry','','[]','看來擾擾總何謀，且把行藏用酒酬。',64,'全唐诗/poet.song.251000.json','["看來擾擾總何謀，且把行藏用酒酬。", "籬菊趁陰移別逕，江楓向晚落行舟。", "秋蟲在壁催人織，歸燕辭巢戀主愁。", "今日去年風物異，錢塘還在望山樓。"]'),
('8c178e02-5bca-45c8-a359-9ea02aee7591','題蕭季賢雪澗軒','陳宗遠','宋','宋诗','song-poetry','','[]','避喧寬結小茅廬，庭竹栽多引鳳棲。',64,'全唐诗/poet.song.251000.json','["避喧寬結小茅廬，庭竹栽多引鳳棲。", "滿地松釵風嘯木，隔窗漁艇月涵溪。", "歸鴻目送雲間失，賀燕巢成棟外低。", "料想春殘曾有夢，謝家芳草綠將齊。"]'),
('c3bf30f5-8f45-48e6-a966-a5b5abdda622','呈陳介叔','陳宗遠','宋','宋诗','song-poetry','','[]','青帝東來駕綵韉，燒燈過後少晴天。',64,'全唐诗/poet.song.251000.json','["青帝東來駕綵韉，燒燈過後少晴天。", "逢春已辦穿花屐，阻雨先尋載酒船。", "但覺野雲生樹外，不知溪水漲灘前。", "落梅有恨香還濕，不得飛來傍舞筵。"]'),
('05564932-4d99-43a7-8d28-ce370c780d38','春日書景','陳宗遠','宋','宋诗','song-poetry','','[]','狼藉殘梅滿地香，遊蜂終日趁晴忙。',64,'全唐诗/poet.song.251000.json','["狼藉殘梅滿地香，遊蜂終日趁晴忙。", "芳堤細草鱗鱗綠，深院垂楊裊裊黄。", "暖霧未消山失木，春風無力曉侵裳。", "眼看景物關情甚，亟把詩吟送一觴。"]'),
('3d6610d6-a01f-4ba7-857d-2207e5c4c4b9','冬晚','陳宗遠','宋','宋诗','song-poetry','','[]','簷樂無風靜自鳴，開窗亦復使眸醒。',64,'全唐诗/poet.song.251000.json','["簷樂無風靜自鳴，開窗亦復使眸醒。", "投林倦鳥低翻翼，觸紙癡蠅細有聲。", "籬外半懸紅子落，牆間少見綠莎明。", "陽生陰後春來近，準擬新詩爲發萌。"]'),
('8d5ffb25-dffe-4b68-870f-09d43d1d2544','因雨遣興','陳宗遠','宋','宋诗','song-poetry','','[]','細雨冥冥風頓凄，微沾沙路不成泥。',64,'全唐诗/poet.song.251000.json','["細雨冥冥風頓凄，微沾沙路不成泥。", "珠排簷網凝絲重，瓊積荷盤壓柄低。", "青草岸頭三月暮，黄梅葉外一山迷。", "小塘水滿魚過塹，隨浪流溝入古溪。"]'),
('fd851bea-1a2f-4ff0-9ec3-e89ca1097e9f','春雨遣興','陳宗遠','宋','宋诗','song-poetry','','[]','靜看何物不關情，屋角青梅子已成。',64,'全唐诗/poet.song.251000.json','["靜看何物不關情，屋角青梅子已成。", "巢拂舊塵迎社燕，花移新樹欲流鶑。", "寒生簾幙深春雨，暖卜園林甚日晴。", "病起無聊休把酒，東君去住亦堪驚。"]'),
('400175b6-0f84-4703-85e4-8c7394f8f329','題汪表叔對袁府起借軒和韻','陳宗遠','宋','宋诗','song-poetry','','[]','朱門虛老濟川材，鏡面芙蕖取次開。',64,'全唐诗/poet.song.251000.json','["朱門虛老濟川材，鏡面芙蕖取次開。", "莫怪偷光鄰士壁，絕勝附火乞兒堆。", "拂塵尚欠千尋竹，極目何須百尺臺。", "魚鱉不知誰是主，也隨流水向東來。"]'),
('e4f689f9-b1c9-439f-a121-75766b38d77e','傳聞八月十四日唱名','陳宗遠','宋','宋诗','song-poetry','','[]','北斗三魁夜吐芒，競傳臚唱擢王揚。',64,'全唐诗/poet.song.251000.json','["北斗三魁夜吐芒，競傳臚唱擢王揚。", "遥知天上輪光滿，先放人間桂籍芳。", "失笑月烏空繞匝，那知雲雁不成行。", "姮娥留取十分好，萬里清輝分外彰。"]'),
('240ebc88-3d66-4fcb-a166-f79195624f57','代壽','陳宗遠','宋','宋诗','song-poetry','','[]','自上黄樞贊萬機，曾將謀略定邊陲。',64,'全唐诗/poet.song.251000.json','["自上黄樞贊萬機，曾將謀略定邊陲。", "平淮便放裴公逸，去越猶嫌范相遲。", "瀲灧池塘蓮萬朵，嬋娟亭館竹千枝。", "居東賸有明農志，歸衮應賡七月詩。"]'),
('91a07850-86cc-4b07-b6b9-e79098084bc9','代壽某帥二首  其一','陳宗遠','宋','宋诗','song-poetry','','[]','當年禁履上星辰，便合登庸秉國鈞。',64,'全唐诗/poet.song.251000.json','["當年禁履上星辰，便合登庸秉國鈞。", "蓋海旌幢紆出鎮，濟川舟楫已知津。", "但從渤澥清沂泗，肯把關河自越秦。", "醖釀早成六月雨，一朝翻手洗炎塵。"]'),
('e6af414b-e8ba-48b1-930f-7ee5f90cafb2','代壽某帥二首  其二','陳宗遠','宋','宋诗','song-poetry','','[]','三年姬衮尚居東，官府清平冠六雄。',64,'全唐诗/poet.song.251000.json','["三年姬衮尚居東，官府清平冠六雄。", "仙洞蟠桃紅映日，山亭修竹綠梳風。", "已將儒雅安時俗，更即人和驗歲豐。", "儉幕棲身無以頌，元龜遊戲出蓮叢。"]'),
('3bc7997f-d8d5-45ed-8864-e164faabde70','壽陳府博','陳宗遠','宋','宋诗','song-poetry','','[]','三嶼縈紆秀且奇，苕華琢采妙工倕。',64,'全唐诗/poet.song.251000.json','["三嶼縈紆秀且奇，苕華琢采妙工倕。", "高羅絳帳聲盈耳，戲著斑衣笑解頤。", "魚藻留連依水密，鳳筩準擬向陽吹。", "的知梅信傳東閣，先訪南宮第一枝。"]'),
('55356b5a-0d3d-4e15-8b70-d9d559bbc029','代壽帥書三首  其一','陳宗遠','宋','宋诗','song-poetry','','[]','欲看棠陰續世傳，重移星履下鄞川。',64,'全唐诗/poet.song.251000.json','["欲看棠陰續世傳，重移星履下鄞川。", "風薰轅戟清官府，日暖瀛壺小洞天。", "塞外不傳青海箭，幕邊穩泛綠池蓮。", "箇中便是神仙境，何必崆峒訪偓佺。"]'),
('01efef07-6928-4fb2-8069-e706c89972f5','代壽帥書三首  其二','陳宗遠','宋','宋诗','song-poetry','','[]','勳業從來簡帝聰，東溟還復奏膚公。',64,'全唐诗/poet.song.251000.json','["勳業從來簡帝聰，東溟還復奏膚公。", "庭前修竹添新綠，洞裏蟠桃依舊紅。", "野渡橫舟人未老，大川作楫路將通。", "願觀整頓乾坤手，不負當年射六蓬。"]'),
('8e65b7e1-0486-4ed4-aade-b13fbf3682f9','代壽帥書三首  其三','陳宗遠','宋','宋诗','song-poetry','','[]','笑談樽俎有餘歡，不獨民安吏亦安。',64,'全唐诗/poet.song.251000.json','["笑談樽俎有餘歡，不獨民安吏亦安。", "競喜鯫生兼盛賜，那堪鶚表錄微官。", "投機已發千鈞弩，速化仍資九轉丹。", "青眼相逢尤異處，他年翹館舊門闌。"]'),
('64304bbc-a149-4437-9164-8a67282d9fbc','郊祀慶成詩','陳宗遠','宋','宋诗','song-poetry','','[]','寶歷登三禩，觚壇類兩儀。',288,'全唐诗/poet.song.251000.json','["寶歷登三禩，觚壇類兩儀。", "居歆修大報，肇祀述前規。", "景迓初陽吉，齋嚴一月期。", "采章循節儉，緼豫屏紛離。", "輅象停方貢，兵驂却道馳。", "殊庭崇祝告，太室款靈娭。", "黄道晴曦麗，青郊湛露滋。", "龍常騰旎旖，蜺羽勝葳蕤。", "列戟森賓衛，嚴更警禁帷。", "蒼圓尊上帝，黄粹見方祇。", "馥郁陽宮燎，芬芳帝籍粢。", "非烟浮羽籥，叶氣冒尊彝。", "濟濟鏘圓玉，峨峨會采𤪌。", "雲裙紛下逮，月璧粲昭垂。", "合奏諧純繹，登歌美緝熙。", "貳觴勤竢獻，虛次迄親祠。", "翊翊靈施佑，禳禳嘏致祠。", "招摇回左翿，閶闔敞南離。", "侍仗朝紳擁，升樓禁蹕隨。", "臚驩皆岳抃，驛赦霈皇慈。", "都號登瑶冊，追思遺寶龜。", "燕謀端有自，鴻祉浩無私。", "肅穆東朝賀，登閎宣室釐。", "慶綿千歲統，歡奉萬年巵。"]'),
('2dcd2786-2566-48db-a8d0-9b7a2ad1a6f7','送友人','陳宗遠','宋','宋诗','song-poetry','','[]','黄梅浦遠草萋萋，風細孤帆雨後低。',32,'全唐诗/poet.song.251000.json','["黄梅浦遠草萋萋，風細孤帆雨後低。", "漁笛一聲何處作，故山回首白雲迷。"]'),
('04a01848-e861-4ad0-aaf8-8fd5ee7b9dba','憫農','陳宗遠','宋','宋诗','song-poetry','','[]','條桑事了蒸麻急，刈麥人兼種稻歸。',32,'全唐诗/poet.song.251000.json','["條桑事了蒸麻急，刈麥人兼種稻歸。", "作苦那能衣食足，幾多遊冶厭輕肥。"]'),
('f52f5417-a7aa-4aed-aaad-1c651284db90','謝石庵見示櫂歌歎時因以見意','陳宗遠','宋','宋诗','song-poetry','','[]','蘆花裊裊西風急，獨立高樓聞雁聲。',32,'全唐诗/poet.song.251000.json','["蘆花裊裊西風急，獨立高樓聞雁聲。", "志士最傷秋夜月，江南塞北兩般明。"]'),
('9a40fca7-021b-4467-b466-ca2ad3f12339','牽牛花','陳宗遠','宋','宋诗','song-poetry','','[]','綠蔓如藤不用栽，淡青花遶竹籬開。',32,'全唐诗/poet.song.251000.json','["綠蔓如藤不用栽，淡青花遶竹籬開。", "披衣向曉還堪愛，忽見蜻蜓带露來。"]'),
('9f615a3f-47cf-45ee-b9cc-43460eb6444b','舟行','陳宗遠','宋','宋诗','song-poetry','','[]','鷗鷺灘頭帆卸雨，牛羊影外草生烟。',32,'全唐诗/poet.song.251000.json','["鷗鷺灘頭帆卸雨，牛羊影外草生烟。", "漁人撒網潮平晚，柳岸維舟取次眠。"]'),
('8ffc9f4c-b432-446c-867d-3a66a6581c29','靈溪舟中風雨','陳宗遠','宋','宋诗','song-poetry','','[]','斜風吹雨打篷窗，獨棹孤舟向曉江。',32,'全唐诗/poet.song.251000.json','["斜風吹雨打篷窗，獨棹孤舟向曉江。", "沙岸竹洲烟漠漠，青山飛鷺一雙雙。"]'),
('3b902a53-5fda-491f-9472-9857a96658eb','蕭季賢有齋名雪澗求鄙語置諸賢之後勉成四韻','陳宗遠','宋','宋诗','song-poetry','','[]','一派流泉遶坐奇，紅塵不到客來稀。',64,'全唐诗/poet.song.251000.json','["一派流泉遶坐奇，紅塵不到客來稀。", "含烟竹塢朝常失，當戶松陰晚自移。", "想有寒猿當月嘯，應看孤鶴唳風歸。", "火雲六月流金石，絕景應須稱此時。"]'),
('c5015a69-38c5-448d-bf02-2f30a03588ee','宿村','陳宗遠','宋','宋诗','song-poetry','','[]','野畦新雨過，蛙雜水濺濺。',48,'全唐诗/poet.song.251000.json','["野畦新雨過，蛙雜水濺濺。", "風掃竹前地，月明柳外天。", "人過驚犬吠，婦績趁蠶眠。", "舍北數聲櫓，夜歸何處船。"]'),
('a8ebd38b-c68a-4f58-8802-2db64e44741b','出村有題','陳宗遠','宋','宋诗','song-poetry','','[]','一片青莎沒古槎，滿彎流水浸瓊沙。',64,'全唐诗/poet.song.251000.json','["一片青莎沒古槎，滿彎流水浸瓊沙。", "早梅先點臘前蕊，敗菊尚開秋後花。", "落葉盡隨寒月少，好山還被曉雲遮。", "人生到處須回首，暗裏流年損鬢華。"]'),
('4a60d44e-4766-4929-8e81-b8720a844af5','遊招真觀','董杞','宋','宋诗','song-poetry','','[]','溪旁老子宮，古松奮蒼鬣。',144,'全唐诗/poet.song.251000.json','["溪旁老子宮，古松奮蒼鬣。", "修逕烟霏深，中巖祠像設。", "巖頭流雲漫，千丈藤蘿結。", "猿猱躍其間，手疑攀日月。", "巖下緩經行，人間諸想滅。", "文楸飛雹鏗，朱絃浮磬徹。", "此山宇宙初，誰擘坤軸裂。", "六丁曾一戲，萬古留洞穴。", "仙翁昔此棲，還丹成白雪。", "佩環昇倒景，遺臺猶岌嶪。", "菊秋風日佳，歸艎雙槳歇。", "便欲茆三間，於此謝塵劫。"]'),
('2a9be992-d021-4b10-bf4d-c796de1010b7','水泛及門用老杜江漲韻','董杞','宋','宋诗','song-poetry','','[]','雨聲喧晝夜，不斷洶簷流。',48,'全唐诗/poet.song.251000.json','["雨聲喧晝夜，不斷洶簷流。", "籬落維孤艇，溪湖失舊洲。", "訪君無去路，狎我有來鷗。", "濤浪相欺得，衝門鼓白頭。"]'),
('48ebd60f-81fb-47e3-9d61-a72ef4585963','西園','董杞','宋','宋诗','song-poetry','','[]','何處西園好，樓雄說媚川。',48,'全唐诗/poet.song.251000.json','["何處西園好，樓雄說媚川。", "村環春色水，樹带夕陽天。", "客促雲間棹，漁吹浦外煙。", "且來窮燕賞，著句剩流傳。"]'),
('111727fe-10c8-4df6-bcb3-2c7a89119b48','用洪憲韻自述','董杞','宋','宋诗','song-poetry','','[]','壯志摩雲一劍閑，欲屠石堡斬樓蘭。',64,'全唐诗/poet.song.251000.json','["壯志摩雲一劍閑，欲屠石堡斬樓蘭。", "功名努力車登坂，歲月驚心水下灘。", "小小茆茨漁子舍，星星鬢髪腐儒冠。", "高山流水無窮思，整頓瑶琴試一彈。"]'),
('83438334-172a-47e0-9ed4-24007b49f854','過彭蠡湖','董杞','宋','宋诗','song-poetry','','[]','客子扁舟故里還，烟收雨霽出蘆灣。',64,'全唐诗/poet.song.252000.json','["客子扁舟故里還，烟收雨霽出蘆灣。", "浮天浴日重湖水，鎮浪回風四望山。", "遠樹離離飛鳥外，征帆點點斷雲間。", "漁翁活計一篷底，愛汝白鷗相似閑。"]'),
('eb38391b-5d4f-46ff-b8cb-e789b8f055a3','題水陸寺','董杞','宋','宋诗','song-poetry','','[]','殿樓邊翠麓，窗戶俯清湘。',24,'全唐诗/poet.song.252000.json','["殿樓邊翠麓，窗戶俯清湘。", "遊客匆匆去，高僧白日長。"]'),
('cabe5b9b-ccb4-4c3b-a2de-d3852a574b6a','題薝蔔','董杞','宋','宋诗','song-poetry','','[]','春花狼藉餘，六出淨煩熱。',24,'全唐诗/poet.song.252000.json','["春花狼藉餘，六出淨煩熱。", "衲衣凝夜禪，香散深林月。"]'),
('0c1fc74a-766b-4689-b6ee-9b107a8b3fde','阮閣','董杞','宋','宋诗','song-poetry','','[]','陰陰松竹合，幽鳥傍人啼。',24,'全唐诗/poet.song.252000.json','["陰陰松竹合，幽鳥傍人啼。", "一局枯棋罷，曦輪又欲西。"]'),
('c780bd70-e931-4187-a5e0-57dbdf95b4bb','暮春聞張思順歸期','董杞','宋','宋诗','song-poetry','','[]','小園寂寞鎖青春，桃李留花待主人。',32,'全唐诗/poet.song.252000.json','["小園寂寞鎖青春，桃李留花待主人。", "青子已團濃綠底，歸艎猶未到溪濱。"]'),
('f06bd82c-faba-43bf-bd44-5c42b2237775','梅','董杞','宋','宋诗','song-poetry','','[]','略彴低橫露淺灘，瘦筇獨立月華殘。',32,'全唐诗/poet.song.252000.json','["略彴低橫露淺灘，瘦筇獨立月華殘。", "一枝拂掠渾如舊，思入清江烟水寒。"]'),
('bc0c2f5c-b001-4c9b-a427-fb0c4db302a7','涉江采芙蓉','鄧允端','宋','宋诗','song-poetry','','[]','涉江采芙蓉，欲采寄所思。',48,'全唐诗/poet.song.252000.json','["涉江采芙蓉，欲采寄所思。", "所思今何在，望斷天一涯。", "將花照秋水，秋水清且漪。", "行樂不得再，日暮空淒悲。"]'),
('3f3ab6df-2ae0-4729-9b0f-d09a901fe89b','古樂府','鄧允端','宋','宋诗','song-poetry','','[]','梧桐葉落秋容早，夜夜寒蛩泣衰草。',64,'全唐诗/poet.song.252000.json','["梧桐葉落秋容早，夜夜寒蛩泣衰草。", "鳳釵金冷鬢雲凋，可惜紅顔鏡中老。", "音塵望斷沈雙鯉，喚起相思何日已。", "瑣窗人靜月輪孤，六曲屏山冷如水。"]'),
('0571eda5-9488-4f33-9223-94b5638f15ed','過處士山齋','鄧允端','宋','宋诗','song-poetry','','[]','一室蕭疏甚，禪床印佛宗。',48,'全唐诗/poet.song.252000.json','["一室蕭疏甚，禪床印佛宗。", "樹陰生石蘚，茶鼎带松風。", "去去水千里，行行山幾重。", "佩琴與詩卷，回首翠微中。"]'),
('fcd166a9-6eec-4bac-8f71-702940d262b8','遣興','鄧允端','宋','宋诗','song-poetry','','[]','得志心偏壯，謀生事轉疏。',48,'全唐诗/poet.song.252000.json','["得志心偏壯，謀生事轉疏。", "雨蓑春種藥，月案夜抄書。", "窮達雖同道，功名不定居。", "憑誰報消息，爲問近何如。"]'),
('b29b6cf8-e5eb-44ff-b707-ca3566551a6c','題社友詩稿','鄧允端','宋','宋诗','song-poetry','','[]','詩裏玄機海樣深，散於章句斂於心。',64,'全唐诗/poet.song.252000.json','["詩裏玄機海樣深，散於章句斂於心。", "會時要似庖丁刃，妙處應同靖節琴。", "韻勝想君言外得，字新令我意邊尋。", "癡人說夢終難信，何日樽前取次吟。"]'),
('fdadce3b-68fd-4525-bfbe-936f0a8079a6','秋興','鄧允端','宋','宋诗','song-poetry','','[]','輕烟漠漠鎖晴嵐，野水溪邊小駐驂。',32,'全唐诗/poet.song.252000.json','["輕烟漠漠鎖晴嵐，野水溪邊小駐驂。", "日暮征鴻落何處，似將風景過江南。"]'),
('637de6a0-e185-4564-b92d-ff5e54160a26','試箋','鄧允端','宋','宋诗','song-poetry','','[]','撥開宿火起爐烟，留得餘香伴夜禪。',32,'全唐诗/poet.song.252000.json','["撥開宿火起爐烟，留得餘香伴夜禪。", "落盡碧桃春不管，東風却放柳飛綿。"]'),
('68769ac6-f8bf-4e25-9351-6b49be510723','絕句','鄧允端','宋','宋诗','song-poetry','','[]','楚岸卸輕帆，停舟曲江曲。',24,'全唐诗/poet.song.252000.json','["楚岸卸輕帆，停舟曲江曲。", "日暮塞鴻歸，春水平橋綠。"]'),
('5a8a84f2-9aa6-45f8-b770-809917c45db7','黄彥與從無逸求妻埋銘以研謝之無逸邀予作歌','董瞿老','宋','宋诗','song-poetry','','[]','君不見昌黎翁，南遷益覺文章工。',208,'全唐诗/poet.song.252000.json','["君不見昌黎翁，南遷益覺文章工。", "滑稽戲作毛穎傳，陶泓之族稱宏農。", "又不見東坡翁，生涯寄食破研中。", "詆訶龍尾尊鳳咮，更誇丹石蒸赤紅。", "古來文士躭翰墨，十有八九坐此窮。", "怪君落筆妙言語，四壁才堪蔽風雨。", "幾年結柳送奴星，文窮跳梁推不去。", "研能窮人君不鄙，爾來諛墓得龍尾。", "緹巾十襲不妄觀，碑字三縑何足擬。", "玉堂視草乃稱之，只恐玄文似揚子。", "君誇此研文似羅，奈君鹿裘带索何。", "我雖忍窮亦好事，尚能搜句爲君歌。", "嗚呼魯公乞米家食粥，不費銀鉤寫珠玉。"]'),
('549956ae-f0e3-4851-9c7b-cd3adf13371e','秋懷五首  其一','李謙','宋','宋诗','song-poetry','','[]','西風入商管，衆木夜有聲。',48,'全唐诗/poet.song.252000.json','["西風入商管，衆木夜有聲。", "候蟲竟何爲，聒聒終夕鳴。", "彼亦有所思，感此歲月征。", "人生豈異適，長嘯一拊楹。"]'),
('33aca62c-c975-4f8f-802c-55876221477c','秋懷五首  其二','李謙','宋','宋诗','song-poetry','','[]','離離牽牛花，縈蔓繞叢棘。',48,'全唐诗/poet.song.252000.json','["離離牽牛花，縈蔓繞叢棘。", "秋風一披拂，苒苒弄寒色。", "物芳時輒改，百歲幾食息。", "長憂髀肉生，悲歌涕霑臆。"]'),
('22e1a943-1344-469d-baf7-bb818c56957c','秋懷五首  其三','李謙','宋','宋诗','song-poetry','','[]','敗壁鳴莎雞，凉月照虛堂。',48,'全唐诗/poet.song.252000.json','["敗壁鳴莎雞，凉月照虛堂。", "南鄰機杼聲，燁燁燈火光。", "遥聞誰家砧，已趣公子裳。", "佳人在何許，葉落山中霜。"]'),
('54c43138-6057-42a6-92ca-ccd20110ea0b','秋懷五首  其四','李謙','宋','宋诗','song-poetry','','[]','英英庭前蘭，密密園中桂。',48,'全唐诗/poet.song.252000.json','["英英庭前蘭，密密園中桂。", "凉飈駕遠馥，素景饒清麗。", "我居無俗物，二子時獨詣。", "願言永爲好，千載成幽契。"]'),
('f495415b-bcb7-46b3-89da-3a2822f28212','秋懷五首  其五','李謙','宋','宋诗','song-poetry','','[]','東籬數叢菊，已著金粟蘂。',48,'全唐诗/poet.song.252000.json','["東籬數叢菊，已著金粟蘂。", "重陽能幾時，使我日屈指。", "向來陶淵明，勿謂今已矣。", "我欲置樽酒，採之雜浮蟻。"]'),
('23a58b12-d5bf-4ee3-989d-2e4e6aacb373','便橋泊舟','項詵','宋','宋诗','song-poetry','','[]','身寄一葉舟，擾擾又行役。',48,'全唐诗/poet.song.252000.json','["身寄一葉舟，擾擾又行役。", "不知寒襲人，但覺酒無力。", "霜剝岸石裂，風激水波逆。", "望眼浩無涯，遠山相對碧。"]'),
('bcb44c01-cf96-4bf3-b7db-0252c2310a03','江西宗派','鄭天錫','宋','宋诗','song-poetry','','[]','西江一水活春茶，寒谷青燈夜撥花。',64,'全唐诗/poet.song.252000.json','["西江一水活春茶，寒谷青燈夜撥花。", "人比建安多作者，詩從元祐總名家。", "宮商迭奏絃邊雁，鼓吹都慚井底蛙。", "身在天南心太史，幾番搔首夕陽斜。"]'),
('571ebf5e-017a-47ad-98e9-9b72ef71bdcf','歸州竹枝詞','無名氏','宋','宋诗','song-poetry','','[]','人鮓甕頭波放顛，兩岸青山青插天。',32,'全唐诗/poet.song.252000.json','["人鮓甕頭波放顛，兩岸青山青插天。", "篙師力盡客破膽，茅屋老翁方醉眠。"]'),
('5e8988e3-56f6-4427-aa5c-6bb67f4073dd','休洗紅','潘葛民','宋','宋诗','song-poetry','','[]','休洗紅，洗多紅色淺。',58,'全唐诗/poet.song.252000.json','["休洗紅，洗多紅色淺。", "不似妾挼藍，挼藍手先染。", "藍深如妾心，郎心紅不禁。", "去去趁春華，封侯早還家。", "願作兔絲蔓，莫學菖蒲花。"]'),
('07a9ed73-f935-4c9e-bf2a-ac58945f5ef0','蝴蝶花','潘葛民','宋','宋诗','song-poetry','','[]','風光白日長，蝴蝶飛過牆。',44,'全唐诗/poet.song.252000.json','["風光白日長，蝴蝶飛過牆。", "飛飛不停去何忙，牆外誰家菜花黄。", "出門不知南陌路，心隨蝴蝶尋郎處。"]'),
('d4af66ce-4947-41be-87c2-c621cfa409ff','舟中聞木犀','李叔達','宋','宋诗','song-poetry','','[]','地近孤城水合流，天風吹下廣寒秋。',32,'全唐诗/poet.song.252000.json','["地近孤城水合流，天風吹下廣寒秋。", "巖花似喜幽人至，先遣清香到小舟。"]'),
('0ad09706-7282-40a5-b304-27efc79f2bed','雪夜問梅','姜補之','宋','宋诗','song-poetry','','[]','一年春事五更初，夢覺寒香乍有無。',32,'全唐诗/poet.song.252000.json','["一年春事五更初，夢覺寒香乍有無。", "門外不知深淺雪，只應消瘦玉肌膚。"]'),
('6d7febce-24e9-4c43-8b02-8dbfc119eb7d','過臨平','黄復之','宋','宋诗','song-poetry','','[]','孤蹤逐浪萍，幾度過臨平。',48,'全唐诗/poet.song.252000.json','["孤蹤逐浪萍，幾度過臨平。", "人語水相應，帆移山倒行。", "鷺飛秋嶼冷，虹飲晚川明。", "不是憑詩句，丹青寫得成。"]'),
('8b6c2c95-b14e-4d79-84fe-eba98b55a05f','題扇面六言','黄復之','宋','宋诗','song-poetry','','[]','峽束天圍漸小，林穿日脚微明。',28,'全唐诗/poet.song.252000.json','["峽束天圍漸小，林穿日脚微明。", "竹居有徑誰掃，水碓無人自鳴。"]'),
('9cc05450-c380-4d6c-95dd-e19eba053d40','浙江晚眺','黄復之','宋','宋诗','song-poetry','','[]','越口對吳頭，風煙畫出秋。',48,'全唐诗/poet.song.252000.json','["越口對吳頭，風煙畫出秋。", "帆遥疑不動，鷗下若相投。", "雲斂山爭出，潮生水逆流。", "平生得意處，盃酒凭江樓。"]'),
('bb3f37c6-89bc-41b5-acb4-d6425c376f84','德清道中','黄復之','宋','宋诗','song-poetry','','[]','天寒歲晚江湖客，一段風煙畫卷昏。',67,'全唐诗/poet.song.252000.json','["天寒歲晚江湖客，一段風煙畫卷昏。", "聚蟹聲喧枯葦{艹斷}，飛鴻影落斷橋村。", "歸雲寺带翠微暝，逆水帆拖白漾渾。", "東去西來見鷗伴，盟寒祇有愧心存。"]'),
('4263fcf2-3864-4b89-a17b-e471bb3ec89f','晚秋山中','黄復之','宋','宋诗','song-poetry','','[]','琅然笑語響空山，兩袖清風倚曲欄。',64,'全唐诗/poet.song.252000.json','["琅然笑語響空山，兩袖清風倚曲欄。", "木落頓驚秋色逈，竹高先覺晚西寒。", "年華流水聲中去，世事浮雲影裏看。", "載酒登臨真解事，人間不似醉鄉寬。"]'),
('67bdf3e0-c1d2-49bd-a2f2-c45ce022dcea','滕王閣','黄復之','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','飛閣岧嶢倚天半，千里秋毫掌中看。',96,'全唐诗/poet.song.252000.json','["飛閣岧嶢倚天半，千里秋毫掌中看。", "城下江聲鐵馬行，梁間日影金蛇竄。", "詞客寂寥光景閑，秀色不改惟西山。", "朝來斂黛作眉語，問此風月何當還。", "便須領略追絕唱，終古發揚無盡藏。", "惜哉元嬰不讀書，筆端祇作蛺蝶圖。"]'),
('f3da9872-68b1-4ddd-9a65-141f161fd9b5','題采石蛾眉山','無名氏','宋','宋诗','song-poetry','','[]','一島烽烟斡怒流，燃犀捉月兩悠悠。',32,'全唐诗/poet.song.252000.json','["一島烽烟斡怒流，燃犀捉月兩悠悠。", "蛾眉中劃三千丈，不著人間半點愁。"]'),
('011d123a-3678-476c-b4fe-1ad07aa8b529','贈翌上人','釋鑒微','宋','宋诗','song-poetry','','[]','京寺別來久，高齋近海隅。',48,'全唐诗/poet.song.252000.json','["京寺別來久，高齋近海隅。", "引禪秋磬動，照像夜燈孤。", "愛水開新沼，思山挂舊圖。", "他時如結社，許繼遠公無。"]'),
('0d0fde60-81ce-476b-ab64-2930ed4b7042','送淳上人歸故山','釋鑒微','宋','宋诗','song-poetry','','[]','舊隠頻關念，秦吳忽倦遊。',48,'全唐诗/poet.song.252000.json','["舊隠頻關念，秦吳忽倦遊。", "離亭逢落日，歸路隔滄洲。", "苔徧安禪石，松侵待月樓。", "重棲上方夜，欹枕瀑聲秋。"]'),
('ea364a4a-2b89-444b-b2e5-a3e27682952b','客愁','釋惠璉','宋','宋诗','song-poetry','','[]','向來春興自不淺，老去客愁還復深。',32,'全唐诗/poet.song.252000.json','["向來春興自不淺，老去客愁還復深。", "半夜蜀禽呼夢破，柳風桃雨總關心。"]'),
('fb4b69e3-4fbd-4d76-8649-eb3b3fed7892','古意','釋惠璉','宋','宋诗','song-poetry','','[]','杏花枝頭蛺蝶飛，似郎遊冶忘歸時。',32,'全唐诗/poet.song.252000.json','["杏花枝頭蛺蝶飛，似郎遊冶忘歸時。", "杏花落盡蛺蝶去，郎不歸來向底嬉。"]'),
('eb4822a3-3b65-4bde-b7d6-e159bed9bb41','別趙莘老','釋惠璉','宋','宋诗','song-poetry','','[]','十里青山照眼，一篷疏雨催詩。',28,'全唐诗/poet.song.252000.json','["十里青山照眼，一篷疏雨催詩。", "記取江邊作別，煙村梅子黄時。"]'),
('154cbcd2-2748-4ccf-8f3a-4ff08e0402c2','書楶上人庵','釋惠璉','宋','宋诗','song-poetry','','[]','雨餘野禽聲斷續，清陰碧流遶茅屋。',32,'全唐诗/poet.song.252000.json','["雨餘野禽聲斷續，清陰碧流遶茅屋。", "道人乞食晚未歸，獨向殘陽淡雲木。"]'),
('da16614f-8207-4edb-9096-0a959dcda38a','野月','釋惠璉','宋','宋诗','song-poetry','','[]','野月今宵滿，小庭人共瞻。',24,'全唐诗/poet.song.252000.json','["野月今宵滿，小庭人共瞻。", "却愁人去後，殘魄獨窺簷。"]'),
('003ab870-63da-4374-9971-98ea27a6bc45','多雨','釋惠璉','宋','宋诗','song-poetry','','[]','盡道春多雨，傷摧花易空。',24,'全唐诗/poet.song.252000.json','["盡道春多雨，傷摧花易空。", "不知春態度，尤在雨陰中。"]'),
('2c58344c-e7a7-409b-820b-71c2bdc40061','舟行寒江曲港','釋惠璉','宋','宋诗','song-poetry','','[]','揚帆出浦又入浦，轉盼順風還逆風。',64,'全唐诗/poet.song.252000.json','["揚帆出浦又入浦，轉盼順風還逆風。", "蘆葉蕭蕭兩岸合，蓼花細細一川紅。", "鷗兼野鶩衝行棹，浪挾汀沙打卧篷。", "行李向來吾自决，漫將晴雨問漁翁。"]'),
('5d9a3d6d-1f9a-4e96-9385-1c7ca443aa3b','梅花','釋惠璉','宋','宋诗','song-poetry','','[]','夢斷笛悲風渚，吹闌月淡烟村。',28,'全唐诗/poet.song.252000.json','["夢斷笛悲風渚，吹闌月淡烟村。", "空想暗香靚色，難招□□□魂。"]'),
('ea3818a6-b323-445d-9a94-02b94e147d6b','句','釋惠璉','宋','宋诗','song-poetry','','[]','瘦倚疏篁半出牆。',8,'全唐诗/poet.song.252000.json','["瘦倚疏篁半出牆。"]'),
('9fce35ba-944e-4a21-95e5-ae1e38df3e72','青城山觀','釋楚巒','宋','宋诗','song-poetry','','[]','靜見門庭紫氣生，前山嵐靄入樓青。',64,'全唐诗/poet.song.252000.json','["靜見門庭紫氣生，前山嵐靄入樓青。", "玉壇醮罷鬼神喜，金鼎藥成雞犬靈。", "巖下水光分五色，壺中人壽過千齡。", "何當一日拋凡骨，騎取蒼龍上杳冥。"]'),
('df0eb442-c25b-4448-ae96-4fc4423b2170','春','釋楚巒','宋','宋诗','song-poetry','','[]','灘漱金沙過枕前，雨絲斜織麵塵烟。',32,'全唐诗/poet.song.252000.json','["灘漱金沙過枕前，雨絲斜織麵塵烟。", "綠楊紅杏宜寒食，紫燕黄鸝聒晝眠。"]'),
('dad733ca-dcde-4578-9d41-79819e5c51a8','隠逸','釋楚巒','宋','宋诗','song-poetry','','[]','杖屨獨遊栽藥圃，琴樽多在釣魚船。',32,'全唐诗/poet.song.252000.json','["杖屨獨遊栽藥圃，琴樽多在釣魚船。", "晚來花下敲門者，不是神仙即酒仙。"]'),
('b4ccfa29-8aaf-4f1e-95e7-e23ef12276bb','句','釋楚巒','宋','宋诗','song-poetry','','[]','臨水鶴窺行道影，隔雲僧認讀書聲。',16,'全唐诗/poet.song.252000.json','["臨水鶴窺行道影，隔雲僧認讀書聲。"]'),
('958b8487-2691-4c8c-a612-84d61e194ee4','石佛寺','釋南越','宋','宋诗','song-poetry','','[]','松竹行纔盡，香城絕世塵。',48,'全唐诗/poet.song.252000.json','["松竹行纔盡，香城絕世塵。", "倚巖開半殿，鑿石見全身。", "鍾鼓中天曉，烟花上界春。", "出門重稽首，願值下生辰。"]'),
('21f888a3-7c2f-43f0-ab29-0ef4fd24729e','登閣','釋清晦','宋','宋诗','song-poetry','','[]','小閣稱幽隠，登臨眺晚晴。',48,'全唐诗/poet.song.252000.json','["小閣稱幽隠，登臨眺晚晴。", "暮雲埋落日，寒樹夾孤城。", "鳥道穿山色，人煙隔水聲。", "自憐疏散意，多不計浮名。"]'),
('5d96a88b-b29e-4804-bd13-c655455b17fd','寄禮導師','釋希雅','宋','宋诗','song-poetry','','[]','掩關名自遠，鯨浪阻相尋。',48,'全唐诗/poet.song.252000.json','["掩關名自遠，鯨浪阻相尋。", "講罷唯澄慮，孤峰祇此心。", "柏烟秋榻靜，蓮漏夜堂深。", "盡仰鄞江上，清風繼道林。"]'),
('ed90ec26-a146-4853-bffa-c227b6658905','秋夕','釋昭符','宋','宋诗','song-poetry','','[]','又是聽猿吟，如何恨更深。',48,'全唐诗/poet.song.252000.json','["又是聽猿吟，如何恨更深。", "每因多病日，減却少年心。", "凍鶴連巖雪，愁人半夜碪。", "故園阻兵革，消息遣誰尋。"]'),
('122ad009-646b-4541-9618-bf7b71ea53e5','落葉','釋正勤','宋','宋诗','song-poetry','','[]','蕭索下疏林，翩翩動客心。',48,'全唐诗/poet.song.252000.json','["蕭索下疏林，翩翩動客心。", "带煙浮遠水，和露逐飛禽。", "近砌凋將盡，前村疊更深。", "年年見衰謝，看即二毛侵。"]'),
('3b576721-8bd0-47ed-9a32-b33f63349be8','葛洪丹竈','釋清外','宋','宋诗','song-poetry','','[]','羽客昔眷此，鍊液奪化功。',24,'全唐诗/poet.song.252000.json','["羽客昔眷此，鍊液奪化功。", "至今寒雲色，挂樹復凝空。"]'),
('df593bd4-72fa-4300-a4d7-d206be8cb6da','寄禮法師','釋擇璘','宋','宋诗','song-poetry','','[]','寺枕滄溟上，門長掩寂寥。',48,'全唐诗/poet.song.252000.json','["寺枕滄溟上，門長掩寂寥。", "定回花漏斷，講徹獸烟消。", "入檻泉聲細，當軒岳色遥。", "何時會重席，南望路迢迢。"]'),
('402acfa7-65fc-4432-9126-bc0d04e8b686','題思安清意太師幽遠庵','釋擇璘','宋','宋诗','song-poetry','','[]','得意幽深觸處真，何須丘壑密藏身。',64,'全唐诗/poet.song.252000.json','["得意幽深觸處真，何須丘壑密藏身。", "愛茲殊勝園林地，非彼等閒花木春。", "白晝杜門人莫到，清談絕俗世難親。", "紛紛閙市繞山脚，獨有此中無點塵。"]'),
('c2dd25bd-dfd4-4e7a-bfe1-deb4bf08840a','牡丹','釋擇璘','宋','宋诗','song-poetry','','[]','東君著力爲渠裁，妙絕真姿不受埃。',32,'全唐诗/poet.song.252000.json','["東君著力爲渠裁，妙絕真姿不受埃。", "嗟我一觀如夢幻，倚欄非爲愛花來。"]'),
('a9ec3489-c789-46ba-a4bd-7a39f92a11c2','詠杜鵑花','釋擇璘','宋','宋诗','song-poetry','','["\u6625\u5929", "\u548f\u7269", "\u548f\u7269\u8bd7"]','春老麥黄三月天，青山處處有啼鵑。',64,'全唐诗/poet.song.252000.json','["春老麥黄三月天，青山處處有啼鵑。", "懸崖幾樹深如血，照水晴花暖欲燃。", "三嘆鶴林成夢寐，前生閬苑覓神仙。", "小山拄頰愁無奈，又怕聲聲聒夜眠。"]'),
('3be29b66-bd1c-467c-bde6-597460a85db4','梅花','釋擇璘','宋','宋诗','song-poetry','','[]','花老香微春始來，禁寒唯有雪相陪。',32,'全唐诗/poet.song.252000.json','["花老香微春始來，禁寒唯有雪相陪。", "無情誰爲添愁怯，雨後風前亦可哀。"]'),
('c7862fc9-902a-43ff-8349-67e70c70aa2d','荷花','釋擇璘','宋','宋诗','song-poetry','','[]','雙雙白鷺墜青空，飛入花汀雜翠紅。',32,'全唐诗/poet.song.252000.json','["雙雙白鷺墜青空，飛入花汀雜翠紅。", "烟火一篷漁舍晚，歸時蕩漾小船風。"]'),
('98df815d-f622-4add-a2c5-f8b3783b47cf','句','釋擇璘','宋','宋诗','song-poetry','','[]','吊古有心懷短李，拂塵無力看豐碑。',16,'全唐诗/poet.song.252000.json','["吊古有心懷短李，拂塵無力看豐碑。"]'),
('95cc9946-8545-4336-837e-dce3ea66299c','楊柳枝','王惲','宋','宋诗','song-poetry','','[]','密葉陰陰漢將營，春風吹斷鼓鼙聲。',32,'全唐诗/poet.song.252000.json','["密葉陰陰漢將營，春風吹斷鼓鼙聲。", "少年不說封侯事，柘彈銅丸落曉鶑。"]'),
('78f80a53-6e56-475a-8a0c-a81eca379744','金陵懷古','陳元鑑','宋','宋诗','song-poetry','','[]','英雄戰守幾春秋，虎踞龍蟠古石頭。',64,'全唐诗/poet.song.252000.json','["英雄戰守幾春秋，虎踞龍蟠古石頭。", "北固只憑江水在，中原長對夕陽愁。", "曹劉謾有經營志，王謝空遺富貴羞。", "舉目便懷千古恨，鳳凰臺上不須游。"]'),
('b71ddf1a-b048-4a9c-9907-094fc78a2e91','送素上人遊方','陳叔堅','宋','宋诗','song-poetry','','[]','不是無衣鉢，師心酷愛山。',48,'全唐诗/poet.song.252000.json','["不是無衣鉢，師心酷愛山。", "自言行脚好，却厭住庵閒。", "野水寒林外，孤雲夕照間。", "清遊何處寺，須寄好碑還。"]'),
('c34c63df-65f5-45b3-bbe4-721df7a85834','竹徑步月','饒良輔','宋','宋诗','song-poetry','','[]','素月流空天不夜，清輝散入疏林下。',32,'全唐诗/poet.song.252000.json','["素月流空天不夜，清輝散入疏林下。", "下有幽人獨往來，杖藜縹緲誰能畫。"]'),
('68ec51e1-7e44-4eba-bf6e-e52bd6176849','秋日寄懷友人','黄深源','宋','宋诗','song-poetry','','[]','幾度裁書無雁休，思君天闊水悠悠。',64,'全唐诗/poet.song.252000.json','["幾度裁書無雁休，思君天闊水悠悠。", "自從席上飛花後，又見江頭落木秋。", "背壁一燈憐瘦影，誰家雙杵動新愁。", "不知今夜西風裏，人倚月明何處樓。"]'),
('ea3cb985-5bad-4bfa-b610-74f0557fbe51','秋思','陳子予','宋','宋诗','song-poetry','','[]','柳岸風條頓老，橘林露葉猶香。',28,'全唐诗/poet.song.252000.json','["柳岸風條頓老，橘林露葉猶香。", "門對一天秋色，人行十里斜陽。"]'),
('2a02f3c3-8b17-4b5f-8995-91b6e1c7f31e','登樓有感','倪龍輔','宋','宋诗','song-poetry','','[]','好趁西風理釣舟，半生書劍兩悠悠。',32,'全唐诗/poet.song.252000.json','["好趁西風理釣舟，半生書劍兩悠悠。", "憑高有恨無人識，空負關河萬里秋。"]'),
('f995cf2a-7e0f-496d-86be-8b08a8e329eb','宮怨','倪龍輔','宋','宋诗','song-poetry','','[]','翠袖無香鏡有塵，一枝花瘦不藏春。',32,'全唐诗/poet.song.252000.json','["翠袖無香鏡有塵，一枝花瘦不藏春。", "十年不識君王面，始信嬋娟解誤人。"]'),
('f1ec4bde-c063-411a-9ad9-afb431d51dbb','酬答','倪龍輔','宋','宋诗','song-poetry','','[]','人生樂處是家山，歸即須歸說便難。',64,'全唐诗/poet.song.252000.json','["人生樂處是家山，歸即須歸說便難。", "吾道何嘗拘出處，丈夫例不怕饑寒。", "一天明月隨詩笠，萬古清風在釣竿。", "浮利浮名儘如許，笑他開眼夢邯鄲。"]'),
('b60aba4b-a8b5-4919-bd14-47ea1427ee25','薔薇','倪龍輔','宋','宋诗','song-poetry','','[]','洛本空藏畫牡丹，海棠出蜀近應難。',32,'全唐诗/poet.song.252000.json','["洛本空藏畫牡丹，海棠出蜀近應難。", "莫嫌村巷薔薇野，春晚猶堪取次看。"]'),
('76e47c43-a670-49df-892b-5650e06a1ffe','藏一山房','倪龍輔','宋','宋诗','song-poetry','','[]','屋小書千古，身閑心五湖。',48,'全唐诗/poet.song.252000.json','["屋小書千古，身閑心五湖。", "從人笑迂闊，於道轉清孤。", "涯涘觀詩硯，陽春借酒壺。", "江邊折黄菊，共感老頭顱。"]'),
('83da2d7b-decc-4bc2-a015-e01c55ba5147','錢謙齋新居','倪龍輔','宋','宋诗','song-poetry','','[]','携琴載鶴又如京，隠處如村却近城。',64,'全唐诗/poet.song.252000.json','["携琴載鶴又如京，隠處如村却近城。", "吳越山從樓外起，江湖水到宅前清。", "草將春色歸新句，梅著寒香暖舊盟。", "最喜出門天咫尺，摩挲老眼看升平。"]'),
('9972578c-23dd-4120-9abe-44a79838a80b','六經','倪龍輔','宋','宋诗','song-poetry','','[]','四十餘萬字，字字寓經綸。',48,'全唐诗/poet.song.252000.json','["四十餘萬字，字字寓經綸。", "其用通天下，何嘗語世人。", "壁藏終有漢，灰冷亦無秦。", "永永扶三極，難窮此道神。"]'),
('3ab24e04-a5fe-47cc-af98-8e029fa8097b','送鄭居之','頼鑄','宋','宋诗','song-poetry','','[]','窗前落葉正蕭蕭，夜雨寒燈共寂寥。',32,'全唐诗/poet.song.252000.json','["窗前落葉正蕭蕭，夜雨寒燈共寂寥。", "君是居人余是客，明朝相候合江橋。"]'),
('ba268f51-5781-4448-ba2c-6ddfaa8dbdc2','枯梅','馬知節','宋','宋诗','song-poetry','','[]','斧斤戕不死，半蘚半枯槎。',24,'全唐诗/poet.song.252000.json','["斧斤戕不死，半蘚半枯槎。", "寂寞幽巖下，一枝三四花。"]'),
('e7141e9e-ebcf-41ad-923f-abcc640ba72b','思友','王克功','宋','宋诗','song-poetry','','[]','孤坐忽太息，拂衣臨長風。',48,'全唐诗/poet.song.252000.json','["孤坐忽太息，拂衣臨長風。", "天高夕月冷，木脫秋山空。", "良晤匪易得，好懷難再同。", "思君不可見，心逐孤飛鴻。"]'),
('589ed3b7-3403-4c23-ad37-17f5af4b79bf','劍浦思歸  其一','王克功','宋','宋诗','song-poetry','','[]','韶華客裏一番老，自嘆此生行路多。',32,'全唐诗/poet.song.252000.json','["韶華客裏一番老，自嘆此生行路多。", "獨上危樓望鄉國，闌干倚遍奈愁何。"]'),
('449c56bb-76e2-48d1-8d2c-c140bfe51079','劍浦思歸  其二','王克功','宋','宋诗','song-poetry','','[]','古柳枝頭啼暮鴉，清明時候又天涯。',32,'全唐诗/poet.song.252000.json','["古柳枝頭啼暮鴉，清明時候又天涯。", "故園桃李憑君問，老却春風幾度花。"]'),
('233604fc-c70d-490c-ba05-a56d59a2fc6c','梅仙山','王克功','宋','宋诗','song-poetry','','[]','芒屩支藤上翠微，長松影裏叩柴扉。',32,'全唐诗/poet.song.252000.json','["芒屩支藤上翠微，長松影裏叩柴扉。", "石壇丹竈蒼苔冷，天闊風高鶴不歸。"]'),
('0b7f01e7-1bea-4dd6-8ee6-020bc9607f24','詠柳','王克功','宋','宋诗','song-poetry','','[]','春到枝枝是綠絲，秋來葉葉是愁眉。',32,'全唐诗/poet.song.252000.json','["春到枝枝是綠絲，秋來葉葉是愁眉。", "灞橋何限經行者，不記尋花繫馬時。"]'),
('873cc713-29d1-4b59-b139-adf7c813cd33','鬻廬','宋氏','宋','宋诗','song-poetry','','[]','自歎年來刺骨貧，吾廬今已屬西鄰。',32,'全唐诗/poet.song.252000.json','["自歎年來刺骨貧，吾廬今已屬西鄰。", "殷勤說與東園柳，他日相逢是路人。"]'),
('f3cde672-6479-4a1e-9293-f832bcf494d3','奉化寶化石巖花鳳','樊圃','宋','宋诗','song-poetry','','[]','山僧取巧蟠珍叢，九苞占盡千葩紅。',32,'全唐诗/poet.song.252000.json','["山僧取巧蟠珍叢，九苞占盡千葩紅。", "倚闌精彩欲飛動，百鳥不敢啼春風。"]'),
('cbedceaf-1df6-458c-9516-eb8ca70d66aa','題毛巔嶺','竺大本','宋','宋诗','song-poetry','','[]','鑿破巖崖砥樣平，要令民旅得通行。',32,'全唐诗/poet.song.252000.json','["鑿破巖崖砥樣平，要令民旅得通行。", "爲君題作毛巔嶺，留取毛巔千古名。"]'),
('5dee820b-c530-4041-b6cc-0727cbdb7b06','瑞香花','張祠部','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曾向廬山睡裏聞，香風占斷世間春。',32,'全唐诗/poet.song.252000.json','["曾向廬山睡裏聞，香風占斷世間春。", "竊花莫撲枝頭蝶，驚覺南窗半夢人。"]'),
('e96ade69-2b63-4b05-b57f-9a05b4f83f59','興化沙溪驛題壁','無名氏','宋','宋诗','song-poetry','','[]','沙溪祇是舊沙溪，今日重來路欲迷。',32,'全唐诗/poet.song.252000.json','["沙溪祇是舊沙溪，今日重來路欲迷。", "獨有暮鴉知我意，白雲深處盡情啼。"]'),
('2fdba97b-6856-463f-a4c8-65770f5ec622','題壁二首  其一','福州僧','宋','宋诗','song-poetry','','[]','不嫌夫婿醜，亦勿厭深村。',24,'全唐诗/poet.song.252000.json','["不嫌夫婿醜，亦勿厭深村。", "但得一回嫁，全勝不出門。"]'),
('1b08067f-8868-4a7e-99d7-899c47e1ab43','題壁二首  其二','福州僧','宋','宋诗','song-poetry','','[]','當初只欲轉頭銜，轉得頭銜轉不堪。',32,'全唐诗/poet.song.252000.json','["當初只欲轉頭銜，轉得頭銜轉不堪。", "何似仁王高閣上，倚欄閑唱望江南。"]'),
('bd7720c3-d433-4244-89ca-f81a8fc8446a','春游','盧梅坡','宋','宋诗','song-poetry','','[]','紅芳滿眼鬬風流，誰信春來有客愁。',32,'全唐诗/poet.song.252000.json','["紅芳滿眼鬬風流，誰信春來有客愁。", "惆悵不干桃李事，故山煙雨憶松楸。"]'),
('5cbec120-8f4c-4fe1-a279-00e85d4dee22','閔雨','盧梅坡','宋','宋诗','song-poetry','','[]','百萬人家井水黄，江南大半田無秧。',32,'全唐诗/poet.song.252000.json','["百萬人家井水黄，江南大半田無秧。", "乖龍豈是爲霖物，貪弄明珠簸日光。"]'),
('4c223865-b08e-4066-92ea-e006a085af7b','梅花','盧梅坡','宋','宋诗','song-poetry','','["\u5199\u96ea", "\u51ac\u5929", "\u52b1\u5fd7", "\u96ea", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u54f2\u7406"]','梅雪爭春未肯降，騷人閣筆費平章。',32,'全唐诗/poet.song.252000.json','["梅雪爭春未肯降，騷人閣筆費平章。", "梅須遜雪三分白，雪却輸梅一段香。"]'),
('85c9e9e9-d5a7-464b-afec-d7a84dd69540','落梅','盧梅坡','宋','宋诗','song-poetry','','[]','自負孤高伴歲寒，玉堂茆舍一般看。',32,'全唐诗/poet.song.252000.json','["自負孤高伴歲寒，玉堂茆舍一般看。", "頑風摧剝君知否，鐵笛一聲人倚欄。"]'),
('c8659f79-4fac-4a19-8ae4-e383a75f9e3e','牡丹','盧梅坡','宋','宋诗','song-poetry','','[]','玉欄四面護花王，一段風流似洛陽。',32,'全唐诗/poet.song.252000.json','["玉欄四面護花王，一段風流似洛陽。", "深院不須驅野鹿，只愁蜂蝶暗偷香。"]'),
('40423459-2308-4749-ab55-537a7a45f0ff','芙蓉','盧梅坡','宋','宋诗','song-poetry','','[]','雲袂飄摇翠佩環，仙姿綽約紫霞冠。',32,'全唐诗/poet.song.252000.json','["雲袂飄摇翠佩環，仙姿綽約紫霞冠。", "雖然謫在西風裏，合作人間小牡丹。"]'),
('4188b2d2-c37b-45ee-b565-e3a7a2b7ded6','荼䕷  其一','盧梅坡','宋','宋诗','song-poetry','','[]','荼䕷結屋是何年，風雨摧頹爲愴然。',32,'全唐诗/poet.song.252000.json','["荼䕷結屋是何年，風雨摧頹爲愴然。", "飛似綠珠樓上墜，困于畢卓甕間眠。"]'),
('2fa41115-9ca1-4923-9029-2fa8bafadeeb','荼䕷  其二','盧梅坡','宋','宋诗','song-poetry','','[]','門前礙路旋移來，壓架欹斜綠作堆。',64,'全唐诗/poet.song.252000.json','["門前礙路旋移來，壓架欹斜綠作堆。", "三月半時花正好，十年前是手親栽。", "幽香早被風偷遞，小蕊那禁雨急催。", "盡數折爲神佛供，免教飛去卧蒼苔。"]'),
('9a5e6164-2b08-41b7-b40e-cdc6af6f53c9','茉莉','盧梅坡','宋','宋诗','song-poetry','','[]','京塵湫隘{山夢}蚊多，彼美繁英玉雪窠。',35,'全唐诗/poet.song.252000.json','["京塵湫隘{山夢}蚊多，彼美繁英玉雪窠。", "見謂嬌柔能特立，肯憑他物學藤蘿。"]'),
('e239c44d-e205-405c-8e08-69d7de7517c4','柳絮','盧梅坡','宋','宋诗','song-poetry','','[]','晴欄看盡柳花飛，一段風情不自持。',32,'全唐诗/poet.song.252000.json','["晴欄看盡柳花飛，一段風情不自持。", "若使化爲萍逐水，不如且作絮沾泥。"]'),
('379b625d-f10a-403c-b58e-d090e64a4760','蠶','盧梅坡','宋','宋诗','song-poetry','','[]','春蠶運巧起經綸，底事周防反殺身。',32,'全唐诗/poet.song.252000.json','["春蠶運巧起經綸，底事周防反殺身。", "鼎鑊如歸緣報主，羞他肥祿避危人。"]'),
('6e5d3154-2085-4918-ae58-db640cb02eb6','讀康節詩','盧梅坡','宋','宋诗','song-poetry','','[]','先生樂處少人知，最是生平不皺眉。',64,'全唐诗/poet.song.252000.json','["先生樂處少人知，最是生平不皺眉。", "身世帝王全盛日，風光伊洛太平時。", "畫前勘破先天易，醉後吟成擊壤詩。", "高卧行窩吾亦願，不堪心事類周嫠。"]'),
('1a7e460f-7e78-47a5-bc29-52570bcd3a24','春暮','王叔安','宋','宋诗','song-poetry','','[]','坐看飛溜落簷牙，吟裏風吹鬢脚斜。',32,'全唐诗/poet.song.252000.json','["坐看飛溜落簷牙，吟裏風吹鬢脚斜。", "洛下牡丹無處處，一枝空插杜鵑花。"]'),
('f64a1f5a-e10d-4872-af6f-ebdcfbcdff80','冬','季昭史','宋','宋诗','song-poetry','','[]','一氣推遷星復回，人生常苦歲華催。',32,'全唐诗/poet.song.252000.json','["一氣推遷星復回，人生常苦歲華催。", "凍雲欲雪雁聲過，臘酒正春梅信來。"]'),
('6ff509c3-0fe5-4f4b-a711-ff231be873b5','寒食','張澮川','宋','宋诗','song-poetry','','[]','江城吹笛晚風斜，城郭人稀噪亂鴉。',32,'全唐诗/poet.song.252000.json','["江城吹笛晚風斜，城郭人稀噪亂鴉。", "火冷烟青寒食過，家家門巷掃桐花。"]'),
('2ac33c76-8059-491a-a4c7-999415b44475','江山晚眺','黄榮仲','宋','宋诗','song-poetry','','[]','十里滄波自在流，滿天風月下蘆洲。',32,'全唐诗/poet.song.252000.json','["十里滄波自在流，滿天風月下蘆洲。", "待携六幅生綃去，畫出江南水墨秋。"]'),
('207258dc-dda7-428f-9433-504b8ef50692','梅花','劉文晦','宋','宋诗','song-poetry','','[]','呼童汲景華，冷浸枝枝雪。',24,'全唐诗/poet.song.252000.json','["呼童汲景華，冷浸枝枝雪。", "伴我山中人，吟殘半窗月。"]'),
('f7410e48-fe39-4cfe-b370-baf0e1f84c81','種梅','劉文晦','宋','宋诗','song-poetry','','[]','佳人天一方，歲暮音書絕。',24,'全唐诗/poet.song.252000.json','["佳人天一方，歲暮音書絕。", "一枝持贈君，猶带去年雪。"]'),
('9b318999-20f8-431a-8172-b6f30e5fc0d9','梅花  其一','王公煒','宋','宋诗','song-poetry','','[]','枯霜剪盡千林葉，纔放江頭第一春。',64,'全唐诗/poet.song.252000.json','["枯霜剪盡千林葉，纔放江頭第一春。", "瘦影看來天愛畫，孤根生處地無塵。", "夜郎歲晚逢羈客，谷口寒雲見似人。", "絕是精神吟不盡，好枝和月插紗巾。"]'),
('c281048f-ccb8-4e6c-8bd9-82ba60c9e40a','梅花  其二','王公煒','宋','宋诗','song-poetry','','[]','雪後梅花獨步天，半開猶自未全然。',64,'全唐诗/poet.song.252000.json','["雪後梅花獨步天，半開猶自未全然。", "倚巖大瘦魂銷夢，照水無塵骨蛻仙。", "貯向金瓶生怕俗，絕饒翠袖敢爭妍。", "夜深霜角吹殘月，錯夢梨花耿獨眠。"]'),
('e6e7929e-fa2a-408d-bbc6-fadfaaf1416c','苔錢','葉豈潜','宋','宋诗','song-poetry','','[]','青錢點點浮鵝眼，綠毯鱗鱗織翠毛。',32,'全唐诗/poet.song.252000.json','["青錢點點浮鵝眼，綠毯鱗鱗織翠毛。", "聚散因風翻覆手，池塘猶喜沒驚濤。"]'),
('8b19360a-a1fc-46c4-bd73-169246fa0b5a','蟬','葉豈潜','宋','宋诗','song-poetry','','[]','柳邊曉立看蟲蛻，化作風餐露宿身。',32,'全唐诗/poet.song.252000.json','["柳邊曉立看蟲蛻，化作風餐露宿身。", "林靜晝長吟不絕，騷騷清苦似詩人。"]'),
('b0b47aa5-de66-4bdb-9c23-09421b989df5','鱖魚','葉豈潜','宋','宋诗','song-poetry','','[]','漁翁今度笭箵富，正是桃花水膩時。',32,'全唐诗/poet.song.252000.json','["漁翁今度笭箵富，正是桃花水膩時。", "網得文鱗如墨錦，貫來楊柳是金絲。"]'),
('90851cbf-5246-4b5e-baf9-dd9fd76eb14b','早梅  其一','張棨','宋','宋诗','song-poetry','','[]','扶筇拄月過前溪，問訊江南第一枝。',32,'全唐诗/poet.song.252000.json','["扶筇拄月過前溪，問訊江南第一枝。", "驛使不來羌管歇，等閒開落只春知。"]'),
('26df3f4b-ace5-4479-af74-7a4105e7d02d','早梅  其二','張棨','宋','宋诗','song-poetry','','[]','何年流水恨，昨夜小橋春。',24,'全唐诗/poet.song.252000.json','["何年流水恨，昨夜小橋春。", "縱有相逢地，都無可寄人。"]'),
('103ff6b1-210d-4ede-bc15-b3b30b1f044c','紅梅','釋璉','宋','宋诗','song-poetry','','[]','嬌朱淺淺透烟光，瘦倚疏簷半出牆。',64,'全唐诗/poet.song.252000.json','["嬌朱淺淺透烟光，瘦倚疏簷半出牆。", "雅有風情勝桃李，巧含春思避冰霜。", "融明醉臉籠輕暈，斂掩仙姿蹙嫩黄。", "旦暮風英墮行袂，依微如著袖中香。"]'),
('7ec2b31a-906d-4754-b1ac-06713f0ba7eb','梨花','趙福元','宋','宋诗','song-poetry','','[]','玉作精神雪作膚，雨中嬌韵越清癯。',32,'全唐诗/poet.song.252000.json','["玉作精神雪作膚，雨中嬌韵越清癯。", "若人會得嫣然態，寫作楊妃出浴圖。"]'),
('c251ca06-9459-4068-9b4a-4209a9ebf05b','茉莉','趙福元','宋','宋诗','song-poetry','','[]','刻玉雕瓊作小葩，清姿元不受鉛華。',32,'全唐诗/poet.song.252000.json','["刻玉雕瓊作小葩，清姿元不受鉛華。", "西風偷得餘香去，分與秋城無限花。"]'),
('f8d523ba-bfe0-4c96-a420-989443083c85','苔錢','趙福元','宋','宋诗','song-poetry','','[]','繞徑玲瓏撒綠錢，田田成百又成千。',32,'全唐诗/poet.song.252000.json','["繞徑玲瓏撒綠錢，田田成百又成千。", "未知買得春多少，草带不妨長短芊。"]'),
('4d913541-4445-4252-b7fb-e92900900f5a','晚鍾','趙福元','宋','宋诗','song-poetry','','[]','花洲人別月凉船，烟寺寒鯨隔岸聞。',32,'全唐诗/poet.song.252000.json','["花洲人別月凉船，烟寺寒鯨隔岸聞。", "带雨一聲天外落，過江穿破半山雲。"]'),
('f47995b6-addb-4ea8-9c34-4b13cb9e10ce','蚊','趙福元','宋','宋诗','song-poetry','','[]','隠隠雷聲語暮天，欺風偷到玉堂前。',32,'全唐诗/poet.song.252000.json','["隠隠雷聲語暮天，欺風偷到玉堂前。", "紗厨浸月凉如水，贏得珠鈿臂上眠。"]'),
('51a98fb7-296b-4d1b-8081-d5c0c9766656','醫兼畫','趙福元','宋','宋诗','song-poetry','','[]','從來藝事兩難精，今日逢君喜且驚。',32,'全唐诗/poet.song.252000.json','["從來藝事兩難精，今日逢君喜且驚。", "不待折肱醫始悟，直須點目畫方成。"]'),
('87d7e366-cdae-401b-a0c9-dbae76ac7f81','桃木','趙福元','宋','宋诗','song-poetry','','[]','神仙擁出蓬萊宮，羅幃繡幙圍香風。',128,'全唐诗/poet.song.252000.json','["神仙擁出蓬萊宮，羅幃繡幙圍香風。", "雲鬟繞繞梳翡翠，頳顔滴滴勻猩紅。", "千嬌百媚粲相逐，爛醉芳春逞芳馥。", "朝陽影裏粲瓊紅，晨霞香中咽寒玉。", "承恩侍宴青帝前，錦衣半脫酣晝眠。", "鶯鶯燕燕扶不起，巧呼苦喚殊可憐。", "傍闌無力嬌欲語，花群本是桃源女。", "幾年流水飯胡麻，今在武陵溪上住。"]'),
('e9947e97-1d2a-4e95-86ff-b5f74d7eabef','壽徐尉','趙福元','宋','宋诗','song-poetry','','[]','神幔亭駕斗浮丹巘，扁題密鏤黄金篆。',289,'全唐诗/poet.song.252000.json','["神幔亭駕斗浮丹巘，扁題密鏤黄金篆。", "淋漓羽蓋森鸞旂，仙凡不隔蟠桃宴。", "紅雲垂地醉壺天，真珠爲漿玉爲饌。", "中有一人長眉青，紫錦荷囊燦星弁。", "金昆玉友相追隨，烏戟琱戈光轉炫。", "皇覽徐公百不憂，衮衮慶源由積善。", "綵童宣敕呼瑞麟，金鏁掣雷奔虎殿。", "瓊胎掇入孔釋送，精神秋水目如電。", "抱琴來訪矩庾仙，溉竹南牆弄詩卷。", "手持造化發生柄，和氣噓枯徧翹端。", "一同按譜學鳴弦，里巷生春無蹇連。", "豈弟君子民父母，肇跡溫麻未之見。", "肘邊疊組斗纍纍，五鶚搏空交剡薦。", "綠綈聯翩閶闔門，催入筍班陪翠輦。", "九重宣補舜衣裳，吐出胸中五色線。", "周公拜前曾拜後，聖朝自有雲屏典。", "朱顔蒼鬢侍玉皇，九轉金丹開鼎鉉。", "芹香儒館忻獻歌，願乞餘圭及雞犬。"]'),
('731f3f4d-05ea-4a55-8248-e2f3b58e1a39','壽趙推官  其一','趙福元','宋','宋诗','song-poetry','','[]','神天枝分秀藹璇杓，光湧銀河半夜潮。',65,'全唐诗/poet.song.252000.json','["神天枝分秀藹璇杓，光湧銀河半夜潮。", "西母誕彌先十日，壽星頒朔恰三朝。", "騎龍曾把黄金斧，駕鳳旋登紫玉霄。", "兩國夫人榮有子，慈宣不老瑞香飄。"]'),
('70ac8107-279b-426d-9755-08c730311e42','壽趙推官  其二','趙福元','宋','宋诗','song-poetry','','["\u8861\u5c71"]','神鬰葱佳氣曉籠天，北斗傾霞入酒舡。',65,'全唐诗/poet.song.252000.json','["神鬰葱佳氣曉籠天，北斗傾霞入酒舡。", "蓮炬金輝油幕下，蘭牙玉立寶香前。", "衡山壽比閩山秀，楚地人瞻福地仙。", "歲歲瑶池聞燕集，蟠桃從此熟三千。"]'),
('34366f5d-2219-476c-80ce-0dba8729d119','芙蓉','邵清甫','宋','宋诗','song-poetry','','[]','三秋猶解强顔紅，絕好清晨風露中。',32,'全唐诗/poet.song.252000.json','["三秋猶解强顔紅，絕好清晨風露中。", "不許涉江人錯認，凌波著土兩家風。"]'),
('53b2f616-8042-4415-a29e-7da94a38f892','桂花','邵清甫','宋','宋诗','song-poetry','','[]','絕憐月殿好根荄，流入人間次第開。',32,'全唐诗/poet.song.252000.json','["絕憐月殿好根荄，流入人間次第開。", "只有君家雙種好，馨香曾達九天來。"]'),
('b8f81dfb-6f13-46c0-97df-47922fd7c303','金錢花','邵清甫','宋','宋诗','song-poetry','','[]','也無稜郭也無神，露洗還同鑄出新。',32,'全唐诗/poet.song.252000.json','["也無稜郭也無神，露洗還同鑄出新。", "青帝若教花底用，牡丹應是得錢人。"]'),
('dd49eb6e-be78-4cfa-a282-f203ca0d33ac','小樓','邵清甫','宋','宋诗','song-poetry','','[]','瓦疊魚鱗棟展虹，清虛容膝小樓東。',64,'全唐诗/poet.song.252000.json','["瓦疊魚鱗棟展虹，清虛容膝小樓東。", "簾高甍聳朝迎日，窗靜櫺疏晝捲風。", "岑遠暮嵐屏隠映，月殘曉影玉玲瓏。", "紗幮一枕華胥夢，看取逍遥田舍翁。"]'),
('104c4aa0-8d9d-4f6e-ad02-98918a2d9f13','牛水滴','邵清甫','宋','宋诗','song-poetry','','[]','銅牛肚裏雖無物，中有深深似澗淵。',32,'全唐诗/poet.song.252000.json','["銅牛肚裏雖無物，中有深深似澗淵。", "牧童不暇閑吹笛，苦爲詩人滴硯泉。"]'),
('7d6711bf-cd99-4b91-93c2-6533ddfbd9ce','壓書石魚','邵清甫','宋','宋诗','song-poetry','','[]','鑿石鎸成一對魚，風流未數玉蟾蜍。',32,'全唐诗/poet.song.252000.json','["鑿石鎸成一對魚，風流未數玉蟾蜍。", "化時換上腰金袋，記取燈窗壓盡書。"]'),
('77efa3ad-c69c-44e5-bbaf-9f6b7fae0b9c','蛟龍筆架','邵清甫','宋','宋诗','song-poetry','','[]','軒昂頭角似真龍，偃仰毛錐有許功。',32,'全唐诗/poet.song.252000.json','["軒昂頭角似真龍，偃仰毛錐有許功。", "直等主人投筆去，定應騰踏入雲中。"]'),
('13d9881a-375f-4639-b752-525538a8d3e7','畫山水扇','邵清甫','宋','宋诗','song-poetry','','[]','巖脈交橫簇亂峰，顛崖懸絕隠仙翁。',32,'全唐诗/poet.song.252000.json','["巖脈交橫簇亂峰，顛崖懸絕隠仙翁。", "不須遠看連天色，盡在吾人掌握中。"]'),
('2f834f9b-6306-4b81-bae4-444904dd2bd1','牡丹','任斯','宋','宋诗','song-poetry','','[]','日落簾垂春日長，懶晴天氣牡丹香。',32,'全唐诗/poet.song.252000.json','["日落簾垂春日長，懶晴天氣牡丹香。", "細看月面天然白，不必姚家宮樣黄。"]'),
('9f6d304f-6488-4d02-88bc-e37de318f2df','牡丹','城山','宋','宋诗','song-poetry','','[]','白帝工夫縷彩霞，肯將顔色弄韶華。',64,'全唐诗/poet.song.252000.json','["白帝工夫縷彩霞，肯將顔色弄韶華。", "酒粘織女秋衣薄，風動嫦娥寶髻斜。", "霜露莫摧今日蕊，輪蹄爭看異時花。", "陰陽造化栽培地，不趁春光有幾家。"]'),
('21edb713-9eba-4367-9a51-d017013f5428','柳','李億','宋','宋诗','song-poetry','','[]','倚岸依依一兩株，溪風吹影暮烟疏。',32,'全唐诗/poet.song.252000.json','["倚岸依依一兩株，溪風吹影暮烟疏。", "青條拂水長如綫，釣叟折來穿白魚。"]'),
('e335318e-8788-4aa4-b551-365ebc98e458','松','謝子才','宋','宋诗','song-poetry','','[]','壯節無雙獨占春，靈根誰肯混凡塵。',32,'全唐诗/poet.song.252000.json','["壯節無雙獨占春，靈根誰肯混凡塵。", "有時雷雨掀天地，疑是蒼龍獨奮身。"]'),
('3e3680b9-48cf-444b-a203-b561fc92f443','三眠柳  其一','謝子才','宋','宋诗','song-poetry','','[]','萬絲繅綠費春工，斜倚闌干枕曉風。',32,'全唐诗/poet.song.252000.json','["萬絲繅綠費春工，斜倚闌干枕曉風。", "兩被流鶑驚夢覺，依前睡趁海棠紅。"]'),
('223141fc-c3ac-41bd-8a0e-322d68f4276f','三眠柳  其二','謝子才','宋','宋诗','song-poetry','','[]','嫩葉吹風不自持，淺黄微綠映清池。',32,'全唐诗/poet.song.252000.json','["嫩葉吹風不自持，淺黄微綠映清池。", "玉人未識分離恨，折向堂前學畫眉。"]'),
('cfec963a-edb9-40b2-9534-490ce5578e3d','郊行','釋惠高','宋','宋诗','song-poetry','','[]','野田分路入誰家，綠樹鳴鶑坎閙蛙。',32,'全唐诗/poet.song.252000.json','["野田分路入誰家，綠樹鳴鶑坎閙蛙。", "過午歇凉人睡足，村村水滿稻吹花。"]'),
('21b1789d-6873-4af2-b5e7-3eadabd74b38','江行','王君謨','宋','宋诗','song-poetry','','[]','暮雲含雨意，江路轉淒清。',48,'全唐诗/poet.song.252000.json','["暮雲含雨意，江路轉淒清。", "夜泊扁舟處，時聞孤雁聲。", "莫愁秋欲老，只是客關情。", "不信他鄉恨，吟邊分外生。"]'),
('2dce9388-a244-436b-aa9e-a1bf792d819b','贈相士','王君謨','宋','宋诗','song-poetry','','[]','江南橋上相逢處，笑我而今似俗人。',32,'全唐诗/poet.song.252000.json','["江南橋上相逢處，笑我而今似俗人。", "要識本來真面目，秋風天地一吟身。"]'),
('b27a368b-eac5-40a1-8351-e21113cae483','溪行','李庭','宋','宋诗','song-poetry','','[]','枯木扶疏夾道傍，野梅倒影浸寒塘。',32,'全唐诗/poet.song.252000.json','["枯木扶疏夾道傍，野梅倒影浸寒塘。", "朝陽不到溪灣處，留得橫橋一板霜。"]'),
('dd79b1c8-258c-4651-b79f-5b11d2c40179','咸陽懷古','李庭','宋','宋诗','song-poetry','','[]','連鷄勢盡霸圖新，兀兀宮牆壓渭濱。',64,'全唐诗/poet.song.252000.json','["連鷄勢盡霸圖新，兀兀宮牆壓渭濱。", "指鹿只能欺二世，沐猴那解定三秦。", "倚天樓觀餘焦土，落日河山幾戰塵。", "今古悠悠同一轍，不須作賦弔前人。"]'),
('1b702fb6-5252-43a7-96ad-127c9e354b98','送裴子法北行','李庭','宋','宋诗','song-poetry','','[]','疋馬區區萬里行，知君雅志爲蒼生。',32,'全唐诗/poet.song.252000.json','["疋馬區區萬里行，知君雅志爲蒼生。", "聖朝若問經邦策，好草囊封勸罷兵。"]'),
('a528a2d2-ab78-4b97-8265-de30842da475','遊廣勝寺東巖','李庭','宋','宋诗','song-poetry','','[]','年來百念如寒灰，老眼慵向時人開。',208,'全唐诗/poet.song.252000.json','["年來百念如寒灰，老眼慵向時人開。", "猶有愛山緣未斷，芒鞋信步東巖隈。", "東巖幽勝甲晉境，寒藤古木生蒼苔。", "誰鑿雲根泄海眼，驚波深瀉如奔雷。", "衲僧具眼覷天奧，作亭闖爾臨淵洄。", "亭中空洞納萬象，收奇攬秀無遺材。", "倚闌清坐洗塵念，灑然冰雪涵靈臺。", "上方一目盡千里，勞筋未暇窮崔嵬。", "百年名剎燼一炬，可憐金碧成蒿萊。", "世間興廢豈足道，會看穹壤論三災。", "短生乘化不暫駐，須臾變化隨風埃。", "心知所歷皆夢境，題詩漫識吾曾來。", "下山一笑便陳迹，但見白塔蒼煙堆。"]'),
('f85f3b65-5d27-467d-bbde-6305a0fc7689','賀羅將仕拜命','李庭','宋','宋诗','song-poetry','','[]','問君爲况近如何，若了青衫好事多。',64,'全唐诗/poet.song.252000.json','["問君爲况近如何，若了青衫好事多。", "待獻嘉謀裨北闕，未容高卧向南坡。", "競辰事業常無倦，垂世功名要不磨。", "應笑柏山疏懶客，羊裘鶴髪釣煙波。"]'),
('4b73fe5e-1f7a-46fa-a8c3-04134dd860ab','賀蕭致政慶恩拜命','李庭','宋','宋诗','song-poetry','','[]','玉立諸郎總席珍，名登天府早榮親。',64,'全唐诗/poet.song.252000.json','["玉立諸郎總席珍，名登天府早榮親。", "讀書聞道超千古，教子如君有幾人。", "行際風雲攀郄桂，先霑雨露及莊椿。", "浮山名壽參天翠，長與藍袍色鬬新。"]'),
('83379e50-efbf-4009-aa88-d53feaa11d04','溪居','郭忠謨','宋','宋诗','song-poetry','','[]','鑿破青山骨，初營數畝丘。',48,'全唐诗/poet.song.252000.json','["鑿破青山骨，初營數畝丘。", "泉分幽竇乳，峽束大江流。", "漁唱來花徑，山光落釣舟。", "沙鷗驚笑語，片片起滄洲。"]'),
('91fbf8b0-2d0b-471e-949d-5903a6b6fa9b','宿石壁山館','郭忠謨','宋','宋诗','song-poetry','','[]','斜陽在山客在船，片帆點破澄江天。',64,'全唐诗/poet.song.252000.json','["斜陽在山客在船，片帆點破澄江天。", "携筇上踏籠頭月，釣篷穩繫蘆花雪。", "夜深野鶴穿雲歸，正是山房酒醒時。", "羽衣起舞謾稱壽，星斗插椽霜滿袖。"]'),
('1d0d5322-cede-4cfa-8616-044dde75bd5f','風月樓','馮艾子','宋','宋诗','song-poetry','','[]','平揖雙峰俯霽虹，近窺喬木欲相雄。',64,'全唐诗/poet.song.252000.json','["平揖雙峰俯霽虹，近窺喬木欲相雄。", "一溪流水一溪月，八面疏欞八面風。", "取用自然無盡藏，高寒如在太虛空。", "落成恰值三秋半，爲我吹開白兔宮。"]'),
('12c2c36b-ce55-4419-a2c7-9deeb38adba5','庵','馮脩之','宋','宋诗','song-poetry','','[]','孤庵半掩門，竹外見前村。',48,'全唐诗/poet.song.252000.json','["孤庵半掩門，竹外見前村。", "地僻山容靜，天陰日色昏。", "風琴鳴木杪，水樂漱雲根。", "蒼壁題詩處，淋漓醉墨痕。"]'),
('f6501c92-e0a7-4c1a-9983-be5a838b13ad','宮詞','林龍遠','宋','宋诗','song-poetry','','[]','桃李六宮寂，君王幸石渠。',24,'全唐诗/poet.song.252000.json','["桃李六宮寂，君王幸石渠。", "臨鸞悔梳洗，女色不如書。"]'),
('b2735bb6-fce7-4e02-b14f-567f15353109','子猷訪戴圖','謝幼謙','宋','宋诗','song-poetry','','[]','溪山雪夜本清奇，底事扁舟只憑歸。',32,'全唐诗/poet.song.252000.json','["溪山雪夜本清奇，底事扁舟只憑歸。", "誰識去來皆興耳，歸時更好似來時。"]'),
('f109b32e-0273-44e1-9c66-d7c9e0dc8d6c','酴唫','謝幼謙','宋','宋诗','song-poetry','','[]','香雪支離半墜風，柔條無奈不成叢。',32,'全唐诗/poet.song.252000.json','["香雪支離半墜風，柔條無奈不成叢。", "阿蠻如許風流骨，打困秋千細雨中。"]'),
('7adcce35-92da-4254-a687-86e65c3d1599','鷺','李春伯','宋','宋诗','song-poetry','','[]','春暗汀洲杜若香，風飄公子白霓裳。',32,'全唐诗/poet.song.252000.json','["春暗汀洲杜若香，風飄公子白霓裳。", "碧天片片忽飛去，何處人家水滿塘。"]'),
('8751f794-3c5c-4486-94e5-d74e0a19d7b3','木芙蓉','李春伯','宋','宋诗','song-poetry','','[]','甚疑牡丹叢，但病皮骨老。',24,'全唐诗/poet.song.252000.json','["甚疑牡丹叢，但病皮骨老。", "不宜入水看，只可隔水眺。"]'),
('0b6be725-8436-4090-85d9-45302cec2813','漁父','鄭夢周','宋','宋诗','song-poetry','','[]','披却蓑衣翁自漁，青荷包飯柳穿魚。',32,'全唐诗/poet.song.252000.json','["披却蓑衣翁自漁，青荷包飯柳穿魚。", "時歸坐在短篷底，白占一溪雲水居。"]'),
