('c9977a8b-2e7f-43b9-bd34-ba8ea4f29a08','寒亭','無名氏','宋','宋诗','song-poetry','','[]','朔風凜凜雪漫漫，未是寒亭分外寒。',32,'全唐诗/poet.song.252000.json','["朔風凜凜雪漫漫，未是寒亭分外寒。", "六月火雲天不雨，請君來此凭闌干。"]'),
('aed557d9-864d-4cbc-b816-98f64be2e6f2','化州','化州郡守','宋','宋诗','song-poetry','','[]','羅川带郭古南州，陵水環城小庾樓。',64,'全唐诗/poet.song.252000.json','["羅川带郭古南州，陵水環城小庾樓。", "雲淡青林無過雁，雨涵丹荔集鳴鳩。", "叨榮銅竹三經夏，勸課農桑屢有秋。", "好趁湍流下吳會，章臺無柳繫歸舟。"]'),
('6334a7fc-4933-45fb-94bc-e4d37e13f6ad','蔡忠惠祀歌 道邊松','無名氏','宋','宋诗','song-poetry','','[]','大義渡至漳泉東，問誰植之我蔡公。',56,'全唐诗/poet.song.252000.json','["大義渡至漳泉東，問誰植之我蔡公。", "歲久廣蔭如雲濃，甘棠蔽芾安可同，委蛇夭矯騰蒼龍。", "行人六月不知暑，千古萬古長清風。"]'),
('0d8a246e-fae6-4bc8-9b2c-17929fa4fbe2','蔡忠惠祀歌 洛陽橋','無名氏','宋','宋诗','song-poetry','','[]','一望五里排琨瑶，行人不憂滄海潮。',56,'全唐诗/poet.song.252000.json','["一望五里排琨瑶，行人不憂滄海潮。", "衝衝來往乘仙飈，蔡公作成去還朝，玉虹依舊橫青霄。", "考之溱洧功何遼，千古萬古無傾摇。"]'),
('ff9c338a-99b0-49e7-b770-827b2e5f7ab2','玉虛觀','劉方','宋','宋诗','song-poetry','','[]','南臺舊觀再焚修，鸞鳳徘徊無樹留。',64,'全唐诗/poet.song.252000.json','["南臺舊觀再焚修，鸞鳳徘徊無樹留。", "芳草滿時迷白鹿，落花深處卧青牛。", "九天宛轉雲常在，萬象縱橫月不收。", "應是廬江人不識，蟾宮遺下水晶樓。"]'),
('0cf31513-3bf3-4f90-8087-32273c26eaa5','清淮樓','張頔','宋','宋诗','song-poetry','','[]','觀魚惠子臺蕪沒，夢蝶莊生冢木秋。',32,'全唐诗/poet.song.252000.json','["觀魚惠子臺蕪沒，夢蝶莊生冢木秋。", "唯有清淮供四望，年年依舊背城流。"]'),
('44f6dfb1-6ce9-4af8-af50-4e2309f78d55','投子山','劉興言','宋','宋诗','song-poetry','','[]','三雄分漢鼎，郊野戰群龍。',24,'全唐诗/poet.song.252000.json','["三雄分漢鼎，郊野戰群龍。", "將軍偶敗北，投子空山中。"]'),
('fc8f8090-d738-45ff-bcc0-7446ea40e356','贈惠演','范置公','宋','宋诗','song-poetry','','[]','相逢三十年前話，記得途中並馬御。',32,'全唐诗/poet.song.252000.json','["相逢三十年前話，記得途中並馬御。", "顧我倦遊成白首，喜君新命得青衫。"]'),
('65ea2c87-f3d2-4db5-bf91-4bacbab1aee3','龍州','邵稽仲','宋','宋诗','song-poetry','','[]','峭壁陰森古木稠，亂山深處指龍州。',32,'全唐诗/poet.song.252000.json','["峭壁陰森古木稠，亂山深處指龍州。", "猨啼鴉噪溪雲暮，不是愁人亦自愁。"]'),
('9d324705-fde9-4491-8e4e-7c2e89cbc9cd','題祖山人池上怪石','張碧','宋','宋诗','song-poetry','','[]','寒姿數片奇突兀，曾作秋山秋水骨。',100,'全唐诗/poet.song.252000.json','["寒姿數片奇突兀，曾作秋山秋水骨。", "先生應是厭風雷，著向池邊塞龍窟。", "我來池上傾醉尊，半酣書破青烟痕。", "參差翠縷擺不落，筆頭驚怪粘秋雲。", "我聞吳中項容水墨有高價，邀得將來倚松下。", "鋪却雙繒直道難，掉首空歸不成畫。"]');
